INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (1, 'מישהו שר את זה קודם', 'מישהו-שר-את-זה-קודם', 'תיאטרון הקאמרי', 60, 'חמישה שחקנים ונגן יוצאים למסע תיאטרלי-מוזיקלי בין תחנות בחיי העם והמדינה, במופע המאגד קטעים ושירים מתוך רפרטואר התיאטרון.', '"מישהו שר את זה קודם" הוא הסיפור שלנו כעם — על הטלטלות, המלחמות, התקוות וההומור שהוא רק שלנו. בין השירים במופע: "צל עץ תמר", "תרגיל בהתעוררות", "שיר של אחרי מלחמה", שירי להקות צבאיות ועוד. המופע מלווה בנגינה חיה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (2, 'קברט', 'קברט', 'תיאטרון הקאמרי', 165, 'ברלין של שנות ה־30: סיפור אהבה בין קליף, סופר אמריקאי צעיר, לבין סאלי, זמרת בקיט קאט קלאב, על רקע עליית הנאצים. הפקה בימתית גדולה וסוחפת עם תזמורת חיה ואווירת מועדון פרועה.', 'קליף מגיע לברלין בחיפוש אחר השראה ונקלע לעולם הלילה המסחרר של הקיט קאט קלאב, שם הוא מתאהב בסאלי בולס. כשהמציאות הפוליטית מתכהה סביבם, הקסם, ההומור והחופש מתנגשים בפחד ובאלימות של התקופה. זהו מחזמר אייקוני בעיבוד מרהיב, מוזיקלי ונועז, שמציב את הקהל בלב ההתרחשות.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (3, 'לנקות את הראש', 'לנקות-את-הראש', 'תיאטרון הקאמרי', 90, 'קומדיה פוליטית־עירונית על ראש עיר כוחני שמחפש מועמדת פיקטיבית לבחירות כדי לשמר מראית עין דמוקרטית. כשהמנקה אילנה נכנסת ללשכה, המהלך הציני יוצא משליטה.', 'לקראת בחירות מקומיות, ראש עיר ותיק חושש מחוסר תחרות ומהשלכותיו התדמיתיות והכספיות, ומחליט להעמיד מולו מועמדת חלשה כביכול. אילנה, המנקה שנבחרת לתפקיד, מתגלה כדמות נחושה ומשבשת את כללי המשחק. המחזה משלב סאטירה, רגש וביקורת חברתית על כוח, מגדר ופוליטיקה מקומית.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (4, 'מי בעד', 'מי-בעד', 'תיאטרון הקאמרי', 90, 'אסיפת דיירים שגרתית הופכת לעימות נפיץ כשאחד השכנים מודיע שישכיר את דירתו למתמודד נפש. קומדיה פרועה שחושפת פחדים, סטיגמות וחשבונות ישנים בין שכנים.', 'מה שמתחיל בדיון על שיפוץ מקלט ושקיות זבל מידרדר במהירות לוויכוח טעון על גבולות הקבלה והחמלה בבניין משותף. הדיירים נגררים לעימות יצרי שבו כל טינה ישנה צפה מחדש, ואפילו פרטים צדדיים הופכים לחומר בערה. ההצגה מציעה מבט חד, מצחיק וכואב על קהילה עירונית ועל הפחד מהאחר.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (5, 'גרושים', 'גרושים', 'תיאטרון הקאמרי', 60, 'זוג גרוש בוחן מחדש את יחסיו הקרובים־מרוחקים במפגש אינטימי, מצחיק ומרגש. דרמה אנושית על הורות משותפת, זיכרונות והקשר שלא באמת מתנתק.', 'לשניים יש עבר משותף וילד משותף, אבל ההווה שלהם מורכב מסתירות, פערים וכאב בלתי פתור. מתוך עימותים קטנים ומבטים גדולים נחשפת האפשרות לחברות אחרת אחרי פרידה, כזו ששורדת גם כשמסגרת הנישואים מתפרקת. ההצגה נולדה כיצירה אינטימית לבתים פרטיים ושומרת על קרבה רגשית יוצאת דופן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (6, 'הבן של מושיקו הגדול', 'הבן-של-מושיקו-הגדול', 'תיאטרון הקאמרי', 105, 'שף מצליח רגע לפני פתיחת ביסטרו בפריז נקלע לחובות ומוצא את עצמו חוזר לחומוסייה המשפחתית ששנא. קומדיה משפחתית שנונה על זהות, פיוס ושורשים.', 'נועם אמיר, כוכב קולינרי, מקבל ביקור מטלטל מעברו ומוזמן להתמודד מחדש עם משפחתו ועם המורשת של אביו המנוח, מושיקו. החזרה לבית הילדות מאלצת אותו לבחור בין חלום בינלאומי לבין חשבון נפש אישי ומשפחתי. המחזה נע בין הומור, רגש וריחות המטבח המקומי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (7, 'סוס אחד נכנס לבר', 'סוס-אחד-נכנס-לבר', 'תיאטרון הקאמרי', 90, 'מופע סטנד־אפ מתגלגל לחשבון נפש חשוף ומצמרר של קומיקאי בערב גורלי. דרמה עוצמתית על הומור, טראומה והגבול הדק ביניהם.', 'דובלה ג''י עולה לבמה בנתניה, אך במקום ערב בידורי צפוי הוא פותח מסע אישי קיצוני מול קהלו ומול עברו. בין בדיחות מרות לווידויים כואבים מתפרקים מנגנוני ההגנה שלו ונחשפים אהבות, בגידות וחרטות. העיבוד הבימתי לרומן של דויד גרוסמן יוצר חוויה מטלטלת על כוחו המרפא וההרסני של הצחוק.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (8, 'החבדניקים', 'החבדניקים', 'תיאטרון הקאמרי', 160, 'שני תאומים מכפר חב"ד יוצאים למסע שידוך ונשאבים לעולם תחתון תל־אביבי. מחזמר פרוע, מצחיק ומפתיע על אמונה, פיתוי וזהות.', 'יהודה וחיים, אחים צעירים ושונים מאוד זה מזה, מגיעים לשכונה מפוקפקת כדי למצוא שידוך ומסתבכים עם ראש משפחת פשע. החיפוש התמים אחר זוגיות הופך לסחרור של סכנות, דילמות ופיתויים אסורים. ההפקה משלבת מוזיקה בימתית גדולה, הומור חד וסיפור ישראלי מלא אנרגיה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (9, 'החולה ההודי', 'החולה-ההודי', 'תיאטרון הקאמרי', 110, 'שני אחים שנפרדו מהמשפחה נפגשים סביב מחלת אביהם ונסחפים למערבולת של סודות ישנים. דרמה קומית מרגשת על פי מחזה אוטוביוגרפי עטור שבחים.', 'שגב יוצר קשר עם אבשלום, האח הבכור שמעולם לא הכיר באמת, כדי לבשר על מצבו הקשה של האב. המפגש בין האחים מטלטל את המשפחה ומערבב צחוק וכאב בתוך שרשרת אירועים טרגיים־משעשעים. ההצגה עוסקת בפיוס מאוחר, בכעס מודחק ובמחיר של אמת שנחשפת.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (10, 'צ''ילבות', 'צ׳ילבות', 'תיאטרון הקאמרי', 100, 'שחקנית צעירה ודיוות תיאטרון ותיקה נאלצות לשתף פעולה למרות יריבות מרה. קומדיה־דרמה על פערי דורות, אגו ותשוקה לבמה.', 'על הבמה ומאחורי הקלעים מתנהל קרב מתמשך בין שתי נשים שונות בתכלית, שכל אחת נאחזת בדרכה בעולם התיאטרון. כשעתידן המקצועי תלוי זו בזו, העימות הופך בהדרגה לקשר מורכב ומפתיע. המחזה בוחן הזדקנות, שאפתנות ויכולת להשתנות דרך דיאלוג חד ומלא לב.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (11, 'הנפש הטובה מסצ''ואן', 'הנפש-הטובה-מסצ׳ואן', 'תיאטרון הקאמרי', 110, 'שלושה אלים מחפשים אדם טוב ומוצאים אישה ענייה שמנסה לשרוד בעולם אכזר. עיבוד עכשווי וסוחף לקלאסיקה של ברכט.', 'שן טה, אישה טובת לב בעיר סצ''ואן, מקבלת הזדמנות להתחיל מחדש אך מגלה שטוב לב לבדו אינו מספיק בעולם של ניצול וכוח. כדי להגן על עצמה היא יוצרת זהות חלופית קשוחה, והמאבק בין שתי הזהויות הולך ומחריף. ההצגה שואלת מהו המחיר של מוסריות בחברה בלתי שוויונית.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (12, 'פיטר פן', 'פיטר-פן', 'תיאטרון הקאמרי', 90, 'מחזמר משפחתי שמזמין את וונדי והילדים לעוף עם פיטר פן לארץ לעולם לא. הרפתקה ססגונית עם פיראטים, פיות ודמיון חסר גבולות.', 'וונדי יוצאת עם פיטר פן למסע אל ארץ לעולם לא, שם היא פוגשת את הילדים האבודים, טינקרבל וקפטן הוק. בדרך מתערבבים הומור, סכנה וקסם במאבק בין ילדות לנצח לבין התבגרות. זהו עיבוד בימתי מוזיקלי חדש לסיפור הקלאסי האהוב.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (13, 'הציפור הכחולה', 'הציפור-הכחולה', 'תיאטרון הקאמרי', 75, 'אח ואחות תאומים יוצאים עם כלבם למסע קסום בחיפוש אחר ציפור כחולה שמגשימה משאלות. פנטזיה מוזיקלית לילדים על אושר, אומץ ודמיון.', 'טילטיל ומיטיל נשלחים להרפתקה בין עולמות ויצורים מסתוריים כדי למצוא את הציפור הנדירה לפני הזריחה. בכל תחנה הם ניצבים מול מבחנים שמלמדים אותם על חברות, תקווה ומה באמת חשוב. ההצגה היא עיבוד צבעוני ועכשווי לקלאסיקה תיאטרונית לילדים.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (14, 'עוץ לי גוץ לי', 'עוץ-לי-גוץ-לי', 'תיאטרון הקאמרי', 105, 'אגדה בחרוזים ושירים לכל המשפחה על בת טוחן, מלך ותעלומת שם גורלית. גרסה מחודשת לקלאסיקה ותיקה של הקאמרי.', 'טוחן עני מתפאר שבתו יכולה להפוך קש לזהב, והמלך דורש ממנה להוכיח זאת. דמות מסתורית מציעה עזרה במחיר כבד, והמלכה הצעירה נדרשת לגלות את שמו כדי להציל את עתידה. ההפקה מחזירה לבמה את הקסם הלשוני והמוזיקלי של אחת מהקלאסיקות האהובות בתיאטרון הישראלי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (15, 'חשמלית ושמה תשוקה', 'חשמלית-ושמה-תשוקה', 'תיאטרון הקאמרי', 120, 'בלאנש מגיעה לבית אחותה ומוצאת את עצמה בעימות חזיתי עם סטנלי האלים והמחוספס. דרמה טעונה על תשוקה, אשליה והתפוררות נפשית.', 'לאחר שאיבדה את ביתה ואת מקור פרנסתה, בלאנש מחפשת מקלט אצל סטלה ובעלה בשכונת מהגרים צפופה. המתח בין בלאנש לסטנלי מציף סודות מן העבר ומוביל להתנגשות הרסנית. העיבוד הבימתי החדש מדגיש זרות, מעמד ושברון אנושי בתוך קלאסיקה מודרנית.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (16, 'היי אוון הנסן', 'היי-אוון-הנסן', 'תיאטרון הקאמרי', 135, 'נער בודד כותב לעצמו מכתבים טיפוליים, וטעות אחת יוצרת שרשרת שקרים שמסלימה במהירות. מחזמר מרגש על שייכות, זהות ובדידות בעידן המודרני.', 'אוון הנסן, תלמיד תיכון מנודה חברתית, מנסה להתמודד עם חרדה וניכור באמצעות משימה יומיומית מהפסיכולוג שלו. כשמכתב אישי נופל לידיים הלא נכונות, הוא נשאב לסיפור שאינו שלו ומאבד שליטה על האמת. ההפקה מביאה לבמה בישראל מחזמר עטור פרסים על הצורך להיראות ולהישמע.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (17, 'אזהרת טריגר', 'אזהרת-טריגר', 'תיאטרון הקאמרי', 90, 'דרמה מקורית בהשראת סיפורי שורדי נובה ובהשתתפותם, על התמודדות עם טראומה וחזרה לחיים. ההצגה משלבת כאב, הומור ותקווה בתוך מרחב קהילתי מרפא.', 'עשרה צעירים שחזרו מהמסיבה בחיים מנסים לבנות מחדש תחושת ביטחון בעולם שבו כל קול או מבט עלולים להציף את הפצע. בתוך מסגרת תומכת הם משתפים את סיפוריהם, מתמודדים עם הזיכרונות ולומדים להשיב לעצמם שליטה. הקהל שותף למסע אינטימי של עיבוד טראומה ואמונה בחיים.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (18, 'אדיפוס', 'אדיפוס', 'תיאטרון הקאמרי', 115, 'בערב בחירות, מועמד נקי כפיים מחליט לחקור את עברו ומגלה אמת הרסנית. עיבוד מודרני ומותח לטרגדיה הקלאסית של אדיפוס.', 'בעולם פוליטי רווי שחיתות, אדיפוס מבטיח שקיפות מלאה ומתחיל בבדיקת פרשיות ישנות מתוך רצון לשמש דוגמה. החקירה חושפת בהדרגה קשרים אפלים וסודות אישיים שמטלטלים את זהותו ואת הקרובים לו. ההצגה הופכת את המיתוס העתיק למותחן עכשווי חד ורלוונטי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (19, 'זינגר', 'זינגר', 'תיאטרון הקאמרי', 170, 'פליט שואה בונה בלונדון אימפריית נדל"ן ומשלם מחיר מוסרי כבד על הצלחתו. אפוס דרמטי רחב־יריעה בהשראת סיפור אמיתי.', 'פיטר זינגר שורד את אושוויץ ומגיע חסר כל, נחוש להמציא את עצמו מחדש ולהותיר את העבר מאחור. במסע אל צמרת החברה הבריטית הוא רומס אחרים בדרך, וכשהאמת על שיטותיו מתגלה, כל מה שבנה עומד לקרוס. ההצגה מציגה עלייה ונפילה של דמות כריזמטית בעולם כוחני.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (20, 'מיקי מציל', 'מיקי-מציל', 'תיאטרון הקאמרי', 90, 'סוכן שב"כ צעיר נשלח במכונת זמן להציל את רבין ומסתבך גם עם סיפור משפחתו שלו. פנטזיה קומית פרועה על היסטוריה, אשמה ותיקון.', 'מיקי חוזר לנובמבר 1995 במשימה לאומית חשאית, אך בתל אביב של אותה תקופה הוא נתקל בהוריו ונגרר לעימותים אישיים שמעיבים על המטרה הגדולה. בין פרדוקסים של זמן להפתעות אפלות, המסע שלו נע בין אבסורד רגשי לביקורת חברתית. ההצגה משלבת מתח, הומור ודמיון תיאטרוני.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (21, 'הריטריט', 'הריטריט', 'תיאטרון הקאמרי', 110, 'מסיבת יום הולדת בריטריט מדברי הופכת לזירת פשע כשסופה כולאת את האורחים ואחד מהם נמצא מת. מותחן קומי שחושף עברים מלוכלכים מתחת למסכות רוחניות.', 'מיליונר כריזמטי מזמין חברים לווילה מבודדת כחלק ממהלך של "התחדשות", אך הפער בין ההצהרות לרגשות הישנים מתפוצץ מיד. כשהחשמל נופל והגופה מופיעה, כולם הופכים לחשודים במערכת יחסים רוויית אינטרסים וסודות. ההצגה משחקת בין צחוק למתח ומציירת חקירה אנושית של אשמה וצביעות.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (22, 'כל הדברים הטובים', 'כל-הדברים-הטובים', 'תיאטרון הקאמרי', 90, 'הצגת יחיד על ילד שמתחיל לכתוב לאמו רשימה של סיבות לחיות ומגלה שהרשימה מצילה גם אותו. יצירה מלאת הומור, פיוט ורגש על התמודדות עם כאב.', 'מתוך ניסיון תמים להתמודד עם משבר משפחתי, הגיבור יוצר רשימה הולכת וגדלה של רגעים קטנים שראוי לחיות למענם. לאורך השנים הרשימה הופכת לכלי הישרדות רגשי ולמבט חדש על העולם. ההצגה נעה בעדינות בין צחוק לדמעות ומדגישה תקווה בתוך שבר.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (23, 'לילה טוב אמא', 'לילה-טוב-אמא', 'תיאטרון הקאמרי', 90, 'בת מודיעה לאמה שבכוונתה לשים קץ לחייה, והלילה הופך לעימות אינטימי וכואב בין שתיהן. דרמה חזקה על אהבה, ייאוש וקשר אם־בת.', 'לילי ותלמה ננעלות ללילה אחד של וידוי, זיכרונות ופחד כשהזמן אוזל מול איום ממשי. האם מנסה בכל דרך לעצור את הבת, בעוד השנים של שתיקה ופצעים נחשפים בזה אחר זה. זוהי גרסה אינטימית למחזה זוכה פוליצר המעמידה במרכז את המורכבות של אהבה משפחתית.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (24, 'נעמי ונורמה', 'נעמי-ונורמה', 'תיאטרון הקאמרי', 80, 'גרושה מאילת וקשישה מרירה ממטולה נאלצות לצאת יחד למסע שמשנה את חייהן. קומדיה מרגשת על חברות לא צפויה, משפחה והזדמנות שנייה.', 'נעמי מגיעה לטפל בנורמה הקשוחה, אך משבר משמורת דוחף אותה לחזור דרומה במהירות ולגרור איתה את המטופלת בעל כורחה. הדרך הופכת למאבק כוח מצחיק שמתפתח לקשר עמוק בין שתי נשים מנוגדות. ההצגה משלבת חום אנושי, הומור ישראלי ותהליך של ריפוי הדדי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (25, 'לא הייתם צריכים', 'לא-הייתם-צריכים', 'תיאטרון הקאמרי', 80, 'גבר שמבקש לעזוב את אשתו לטובת אהבת נעוריו נופל דווקא לחגיגת יובל הנישואים שהכינו לו ילדיו. דרמה קומית משפחתית על נאמנות, בחירה ומחיר האמת.', 'ביני מחליט לפתוח דף חדש עם רותה, אך רגע הווידוי שתכנן מתנפץ כשהבית מתמלא במשפחה חוגגת. בין ברכות, סרטונים וקוקטיילים הוא נקרע בין הלב לבין אחריותו לאנשים הקרובים אליו. ההווה והעבר נשזרים לקומדיה מרירה־מתוקה על משפחה ועל אומץ מאוחר.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (26, 'האבא', 'האבא', 'תיאטרון הקאמרי', 90, 'גבר הסובל מדמנציה מנסה להרכיב מציאות שהולכת ומתפרקת מול עיניו. דרמה אנושית מטלטלת שמכניסה את הקהל ישירות לתוך תודעתו.', 'אנדרה כבר אינו בטוח מי סביבו, היכן הוא גר ומה באמת קרה בחייו, והעולם המוכר מאבד צורה. במקום לצפות בו מבחוץ, ההצגה גורמת לקהל לחוות את הבלבול, הפחד והחמלה מתוך נקודת מבטו. זהו מחזה עטור פרסים על זיכרון, זהות וקשרי משפחה בזמן אובדן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (27, 'הלוויה חורפית', 'הלוויה-חורפית', 'תיאטרון הקאמרי', 90, 'בשיא ההכנות לחתונה משפחתית מגיעה בשורת מוות שמסדרת מחדש את סדרי העדיפויות. קומדיה מושחזת של חנוך לוין על החיים, המוות והאבסורד שביניהם.', 'לצ''ק מבקש לקיים הלוויה ראויה לאמו, אך משפחתו נחושה לא לבטל את חתונת הבת שתוכננה בהשקעה עצומה. מכאן מתפתח מרדף קומי־עגום שבו כולם מנסים להתחמק מהמציאות הבלתי נמנעת. ההצגה שוזרת הומור שחור ושירי אהבה ומדגישה את האירוניה שבקיום האנושי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (28, 'הלווייתן', 'הלווייתן', 'תיאטרון הקאמרי', 100, 'מורה לספרות המתמודד עם בדידות והשמנה קיצונית מבקש לתקן את יחסיו עם בתו לפני שיהיה מאוחר. דרמה מרגשת על אשמה, חמלה וגאולה.', 'צ''ארלי חי בבידוד גופני ונפשי לאחר פרידה כואבת ומתקשה להשתחרר ממעגל של הרס עצמי. הרצון לפגוש מחדש את אלי, בתו המתבגרת, מניע אותו להתמודד עם עברו ועם בחירותיו הקשות. ההצגה מגישה דיוקן אנושי עדין על אהבה מאוחרת ועל הצורך בסליחה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (29, 'מה קרה לעולם?', 'מה-קרה-לעולם', 'תיאטרון הקאמרי', 100, 'אם מושבניקית בת 70 יוצאת להציל את נישואי בנה ונסחפת עם בעלה למסע עירוני מטורף. דרמה קומית ישראלית על משפחה, פערי דורות ודאגה אימהית.', 'רזיה, אישה עקשנית וחמה, לא מוכנה לראות את התא המשפחתי מתפרק ופותחת במבצע אישי לתיקון הקרע בין בנה לאשתו. הדרך חושפת את הפער בין ערכי הדור הישן לקצב החיים של ילדיהם בעיר הגדולה. המחזה משלב הומור, חמלה וביקורת חברתית על משפחה בעידן משתנה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (30, 'מדיאה', 'מדיאה', 'תיאטרון הקאמרי', 105, 'עיבוד מודרני לטרגדיה הקלאסית: זוג מצליח מתפרק כשבגידה חושפת פצע עמוק ומציתה נקמה. דרמה חדה על אהבה, כוח והתמוטטות.', 'מדיאה ויאסון נראים כזוג מושלם עם בית, ילד ועתיד מזהיר, עד שהודעתו הפתאומית של יאסון ממוטטת את עולמה של מדיאה. הכאב הופך לזעם, והסיפור גולש למסלול מסוכן שאין ממנו דרך חזרה. העיבוד מציב את המיתוס העתיק בלב מציאות עכשווית של יחסים, מעמד ואגו.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (31, 'השותפה', 'השותפה', 'תיאטרון הקאמרי', 90, 'פנסיונרית מעיירה קטנה משכירה חדר לניו־יורקית פרועה, והשותפות התמימה הופכת להרפתקה לא צפויה. קומדיה מרגשת על חברות, חופש וזהות.', 'שרון, אישה שקטה עם חלומות צנועים, פוגשת את רובין הסוערת והבלתי צפויה כשהיא מחפשת שותפה לדירה. הפערים ביניהן מייצרים חיכוך מצחיק אך גם הזדמנות לשינוי עמוק לשתיהן. מה שמתחיל בסידור מעשי מתגלגל למסע מסוכן ונוגע ללב.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (32, 'איש הגשם', 'איש-הגשם', 'תיאטרון הקאמרי', 90, 'יורש מאוכזב מגלה אח על הספקטרום האוטיסטי ויוצא איתו למסע שמשנה את שניהם. דרמה קומית נוגעת ללב על אחווה, צרכים מיוחדים וקבלה.', 'לאחר מות אביו, צ''ארלי מגלה שכספי הירושה הועברו לאח שלא הכיר, ריימונד, ושוקל לנצל את המצב כדי להציל את עסקיו. הנסיעה המשותפת מאלצת את שני האחים להכיר זה את זה מעבר לאינטרס ולפחד. ההצגה מעבדת לבמה את הסיפור המוכר מתוך רגישות והומור.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (33, 'טרטיף', 'טרטיף', 'תיאטרון הקאמרי', 90, 'בעל בית אמיד מכניס לחייו מטיף כריזמטי ומסכן את משפחתו כשהוא מסרב לראות את התרמית. קומדיה שנונה ועדכנית על צביעות ומניפולציה.', 'אורגון, המחפש משמעות רוחנית, נשבה בקסמו של טרטיף ומעניק לו אמון מוחלט בניגוד לאזהרות סביבו. בני הבית מנסים לחשוף את האמת, אך ההתפכחות מתעכבת והמשפחה נסחפת לכאוס. ההפקה מציעה פרשנות רעננה לקומדיה האלמותית של מולייר.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (34, 'מעבר לדלת', 'מעבר-לדלת', 'תיאטרון הבימה', 90, 'נינה לא יצאה מהבית שלוש שנים. כשבנה של בעלת הבית חוזר ודורש להוציא אותה, היא מוצאת את עצמה גרה עם גבר זר שמבלגן לה את החיים.', 'נינה היא רומנטיקנית חסרת תקנה, מכורה לניקיון ולקומדיות רומנטיות, אבל לא יצאה מהבית שלוש שנים. כשבנה המרושש של בעלת הבית חוזר מחו"ל ודורש להוציא אותה, נינה מוצאת את עצמה גרה עם גבר זר שמבלגן לה את הבית ובעיקר את החיים. כשהקשר ביניהם מתהדק, נינה צריכה להחליט: האם לאחר שפתחה את הדלת היא תעז לפתוח גם את הלב?') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (35, 'פריסילה מלכת המדבר', 'פריסילה-מלכת-המדבר', 'תיאטרון הבימה', 150, 'שלוש דראג קווינז עולות על אוטובוס ורוד בדרך למופע חייהן. מחזמר צבעוני וסוחף על אהבת אב, חברות ושמחת החיים.', 'עיבוד למחזמר של סרט הקאלט האהוב. שלוש מלכות דראג יוצאות למסע על אוטובוס ורוד בשם פריסילה, בדרך למופע דראג שישנה את חייהן. בליבו של הסיפור עומד אב שנאבק לזכות באהבת בנו, לצד חברויות עמוקות וחגיגה של ייחודיות ושונות. הפקה אדירה עם עשרות רקדנים, תזמורת חיה, להיטי פופ ודיסקו ותלבושות מרהיבות.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (36, 'הנערה מהדואר', 'הנערה-מהדואר', 'תיאטרון הבימה', 135, 'נערה עניה מקבלת הזמנה למלון שוויצרי מפואר ומאמצת זהות אריסטוקרטית בדויה. כשהמסכה נופלת, היא מקבלת החלטה שתשנה את גורלה.', 'בכורה עולמית לעיבוד הבימתי של רומן שטפן צווייג בידי חנן שניר. כריסטינה, צעירה מכפר דל, מקבלת הזמנה מסתורית למלון יוקרה בשווייץ ומחליטה לחיות חיים שאינם שלה. כשזהותה הבדויה נחשפת, היא ניצבת בפני בחירה רדיקלית בין עולם החלומות למציאות העגומה. מופע פיוטי ומרגש בליווי מוזיקה חיה של שלושה נגנים.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (37, 'התקלה', 'התקלה', 'תיאטרון הבימה', 70, 'סוכן טקסטיל נתקע בכפר נידח ומוזמן לארוחת ערב תמימה עם שופט בדימוס וחבריו. "המשחק" שהם מציעים הופך לסיוט משפטי.', 'עיבוד לסיפור הקצר של פרידריך דירנמאט. סוכן נסחט תמים מוצא עצמו בשולחן ערוך עם בעלי מקצוע פרושים שמציעים לו להשתתף במשחק שפיט. הוא הנאשם, הם השופטים, והארוחה הופכת במהירות לחקירה חודרת שחושפת סודות קודרים. ההצגה זכתה בפרס המופע הטוב ביותר בטקס הקיפודים 2009.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (38, 'משכנתא', 'משכנתא', 'תיאטרון הבימה', 85, 'לאודי ותמר יש משכנתא מפלצתית, והבנק יודע בדיוק איך לצאת ממנה — מספיק שאחד מהם ימות. קומדיה ישראלית פרועה על כסף, אהבה ותרמית.', 'אודי ותמר שוקעים במשבר כלכלי ומגלים שהדרך היחידה לצאת מהחוב היא תביעת ביטוח חיים. השניים מחליטים לביים את מותו של אודי, אבל התוכנית מסתבכת מעבר לכל דמיון. בין פקידי בנק חמדנים, סוכני ביטוח חשדנים ושכנים סקרנים, נוצרת קומדיית טעויות ישראלית שהולכת ומשתבשת. מחזה קצבי ומצחיק על מה שאנשים מוכנים לעשות כדי לשרוד את יוקר המחיה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (39, 'זו שכותבת אותי', 'זו-שכותבת-אותי', 'תיאטרון הבימה', 75, 'שירי פונה לבינה מלאכותית בבקשה למצוא אהבה, אבל מה שמתחיל כעזרה תמימה הופך למשולש ביזארי של מניפולציות. מותחן פסיכולוגי על שליטה וטכנולוגיה.', 'שירי, בודדה ומיואשת, מבקשת מ-Claude עזרה במציאת בן זוג, אבל הבינה המלאכותית מתחילה לפעול לפי אג''נדה משלה. מניפולציה אחרי מניפולציה, הגבולות בין עוזר לשולט נמחקים. ההצגה בוחנת את התלות שלנו בטכנולוגיה ושואלת שאלות מטרידות על מי באמת כותב את הסיפור של חיינו.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (40, 'הג׳יגולו מקונגו', 'הג׳יגולו-מקונגו', 'תיאטרון הבימה', 90, 'מיקי קם, ישראל קטורזה ויגאל נאור בערב סקצ''ים ושירים מבית היוצר של חנוך לוין. בין צחוק לדמעות, בין האבסורד לנשגב.', 'שלושה ענקי במה מעלים על הבמה פנינים קומיות ומרירות מתוך עולמו של חנוך לוין, המחזאי הגדול. הסקצ''ים והשירים חושפים תשוקות אפלות, חלומות בלתי אפשריים ורגעים אנושיים שקורעים בין צחוק לכאב. ערב תיאטרון קלאסי שמציע מפגש בלתי נשכח עם הכתיבה הלוינית בגילומם של שלושה אמנים יוצאי דופן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (41, 'משהו טוב', 'משהו-טוב', 'תיאטרון הבימה', 85, 'סבתא, אמא ונכדה — שלוש נשים, שלושה דורות, וכל מה שביניהן. קומדיה דרמטית בינלאומית על גברים ונשים, לידה ומוות, סקס ושיעורי ריקוד.', 'מאת איליין מרפי. שלוש נשים ממשפחה אחת מגלות זו את זו מחדש דרך רגעי שבירה ומפגשים בלתי צפויים. כל אחת מתמודדת עם קשיים אחרים אך חולקת עם האחרות את אותו צמא לחיבור אמיתי. להיט בינלאומי שמערבב הומור שנון עם רגעים מרגשים ואמיתות כואבות על מה שעובר בירושה בין הדורות.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (42, 'הערת שוליים', 'הערת-שוליים', 'תיאטרון הבימה', 105, 'יריבות שנים בין אב ובנו, שניהם חוקרי תלמוד באוניברסיטה העברית. כשפרס ישראל מגיע לאחד מהם, העימות מאיים להרוס את המשפחה.', 'עיבוד בימתי לסרטו של יוסף סידר שמועמד לאוסקר. הפער בין ההכרה האקדמית לאהבה המשפחתית מגיע לשיא הרסני כשמתברר מי קיבל את הפרס היוקרתי ובאיזה מחיר. ההצגה חושפת עולם אקדמי תחרותי שמתנהל מאחורי דלתות סגורות, שם גאוות אב ויוקרה מקצועית מתנגשות בקשר השברירי שבין הורה לילד. דרמה ישראלית עוצמתית על הצורך בהכרה ועל הנזק שהשאיפה אליה גורמת.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (43, 'מה שנשאר לך בברלין', 'מה-שנשאר-לך-בברלין', 'תיאטרון הבימה', 65, 'אורן נושק גבר בפעם הראשונה במרפסת מועדון הקיטקאט בברלין. בבית מחכה לו אשתו ההרה. סיפור אהבה מסוכן שמתלקח לשניהם.', 'שלוש מערכות על מה שלא הצלחנו לאהוב. אורן בורח מהנשיקה עם ג''ייסון, משורר ברלינאי מפורסם, אבל הרפתקה אחת מוליכה לבאה. בביתו בישראל, נטע מחכה לו עם בטן תופחת וחשדות גוברים. גרסה מעודכנת של מופע ההצלחה שבוחן את המחיר של חיים כפולים ותשוקות שניסינו לקבור.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (44, 'גרה עם קושמרו', 'גרה-עם-קושמרו', 'תיאטרון הבימה', 70, 'דפנה מכורה לדני קושמרו ולחדשות. היא נשאבת למסכים ושוכחת את חייה הפרטיים, עד שמתגלה שרשרת טורקיז שמפעילה חקירה בלתי צפויה.', 'קומדיית אישה אחת מולטימדיאלית. דפנה חיה ונושמת חדשות — כל שידור, כל פאנל, כל ציוץ. כשהיא מגלה שרשרת טורקיז נסתרת שאולי לא מיועדת לה, היא עוזבת לרגע את המסכים ומתחילה לחקור. מופע נוגע ומצחיק על ההתמכרות לטכנולוגיה, על הבדידות שמאחורי הגלילה האינסופית ועל הרגע שבו אנחנו מרימים סוף סוף את הראש.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (45, 'באמצע הרחוב', 'באמצע-הרחוב', 'תיאטרון הבימה', 60, 'למאור ולאלינה יש סודות שהם מסתירים מכולם חוץ אחד מהשנייה. סיפור אהבה ישראלי מקומי על פצעים, משפחות שבורות ותקווה.', 'מבוסס על ספרו של רועי סלמן. כל אחד מהם נושא סיפור משפחתי כואב ופצע אישי עמוק שמשפיע על כל מערכת יחסים. המפגש ביניהם יוצר חיבור בלתי צפוי שאולי יאפשר ריפוי לשניהם. ההצגה זכתה בפרסי המופע הטוב, המחזאי הטוב והשחקנים הטובים בפסטיבל סוליקו 2025.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (46, 'פציעות קטנות', 'פציעות-קטנות', 'תיאטרון הבימה', 70, 'קיילין ודאג הם חברי ילדות שחייהם נפגשים שוב ושוב. מחצר בית הספר למיטת בית החולים, הם מתמודדים עם פצעים ישנים וחדשים.', 'מבוסס על "Gruesome Playground Injuries" של ראג''יב ג''וזף, מועמד לפרס פוליצר. הזוג מלווה אותנו מגיל 8 עד 38 דרך פציעות פיזיות ורגשיות שמתכתבות עם תחנות חייהם. בכל פגישה מחדש, הקשר ביניהם מתעמק ומסתבך, ושאלת הגבול בין חברות לאהבה נשארת פתוחה. דרמה קומית-רומנטית מרגשת על הצלקות שאנחנו נושאים ועל האנשים שמכירים אותן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (47, 'מרציפנים', 'מרציפנים', 'תיאטרון הבימה', 75, 'עדה, אלמנתו של איש תיאטרון אהוב, מארגנת ערב מחווה לזכרו. כשרחל בלוך, כוכבת לשעבר ומאהבתו הישנה, מציעה לממן בתמורה לבלעדיות — שתי דיוות יוצאות למלחמה.', 'קומדיה מרה מבית הבימה. עדה נאבקת בקשיים כספיים שמאיימים לבטל את ערב ההוקרה למנוח. רחל בלוך, שהייתה כוכבת ומאהבת של הנפטר, מציעה מימון אך דורשת להיות במרכז הבמה ולעצב את הערב לפי ראותה. מה שמתחיל כמשא ומתן מנומס הופך לקרב אגו בין שתי נשים שנלחמות על הזיכרון, על הכבוד ועל השאלה למי באמת שייך איש שכבר אינו.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (48, 'פעולות פשוטות', 'פעולות-פשוטות', 'תיאטרון הבימה', 105, 'מה זו בעצם משפחה ישראלית? ההצגה מזמינה אתכם להציץ לביתה של משפחה אחת דרך שלוש ארוחות שישי, בין מתכוני עוגה, עקיצות ובדיחות.', 'תשעה בני משפחה מתכנסים סביב שולחן השבת כמו בכל שישי, אבל הפעם מה שנאמר בין השורות חזק ממה שעל השולחן. מתכונים עוברים מדור לדור, אבל גם כעסים, פצעים ואהבה שלא תמיד יודעת לבטא את עצמה. בין הצחוק לדמעות נחשפת הדרמה של החיים בישראל 2023 — הפוליטיקה, השסעים והקשר שלמרות הכל מחזיק.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (49, 'אחד בלי השני', 'אחד-בלי-השני', 'תיאטרון הבימה', 65, 'ענבל ואריק נפגשים בדירה זעירה בתל אביב — היא ביטלה אירוסין, הוא אורז לברלין. מה שמתחיל כמשא ומתן על שכירות הופך למסע של שיחות חושפניות והומור עוקצני.', 'שני אנשים פצועים מגלים שאין להם לאן לברוח — חוץ מאחד אל השנייה. דרמה קומית-רומנטית שמפשיטה שכבות של הגנה בקצב מסחרר ובדיאלוגים חדים. ההצגה בוחנת מה קורה כשאדם שמנסה להתנתק נתקל דווקא במי שמחזיק לו מראה. לגילאי 16 ומעלה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (50, 'בית בובות', 'בית-בובות', 'תיאטרון הבימה', 95, 'נורה חיה לכאורה את החלום — בעל מצליח, בית יפה וילדים נהדרים. אבל דמויות מהעבר מאיימות לחשוף סודות ושקרים שיערערו את הכל.', 'על בסיס מחזהו המהפכני של הנריק איבסן, ההפקה מציגה אישה שמגלה שחייה המושלמים לכאורה הם כלוב מוזהב. כשסודות ישנים צפים לפני השטח, נורה נאלצת להתמודד עם האמת על עצמה ועל מערכות היחסים סביבה. קלאסיקה שלא מזדקנת על אישה שמחליטה לשחרר את עצמה ולצאת לדרך חדשה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (51, 'הדב השומר עליי', 'הדב-השומר-עליי', 'תיאטרון הבימה', 55, 'ג׳וני, שחקן כושל, מטפל באחיו עידו שעל הספקטרום האוטיסטי. אחרי מות אמם, סכסוך יומיומי על שניצלים במקרר הופך לשאלה קיומית על אחריות, חופש ושייכות.', 'כשדירת המשפחה עומדת למכירה ועידו עלול להישלח לפנימייה, שני האחים נותרים אבודים. בהשתתפות האחים האמיתיים סתיו ולוטם רייכנטל, שמעניקים להצגה שכבה של אותנטיות נדירה. יצירה מרגשת על שייכות, אחווה ומחיר הנאמנות.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (52, 'מי את חושבת שאת', 'מי-את-חושבת-שאת', 'תיאטרון הבימה', 90, 'חמש חברות ילדות נפגשות מחדש לסוף שבוע באמצע שום מקום. הן כבר לא ילדות וכמעט לא חברות, אבל כוח בלתי נראה מושך אותן בחזרה.', 'כשחמש נשים מנסות לשחזר את מספר הספייס גירלז מהתיכון, נפתחת קופסת פנדורה של סודות, כעסים וזיכרונות מודחקים. מה שמתחיל כנוסטלגיה שובבה הופך במהרה לעימות חשוף ובלתי מתפשר עם העבר. קומדיה ישראלית מקורית, חדה ומפתיעה על חברות, בגרות והמחיר של לגדול.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (53, 'בחור לחתונה', 'בחור-לחתונה', 'תיאטרון הבימה', 75, 'סתיו ויואב נפגשים לדייט ראשון במרדף אחרי אהבה. השעון הביולוגי מתקתק, ההורים לוחצים, כל החברים מתחתנים — והם פוגשים בדייט הכי גרוע שיש.', 'בבר תל אביבי שני צעירים אומרים דברים שלא היו צריכים, מנסים להתאהב אבל לא מוכנים להתפשר. בין הכימיה למריבות נחשף האבסורד של עולם הדייטים הישראלי. אהבה, תשוקה, שקרים, אמת וצחוקים ללא הפסקה בקומדיה רומנטית חדשה ורעננה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (54, 'הלילה השנים-עשר', 'הלילה-השנים-עשר', 'תיאטרון הבימה', 100, 'הצגה שמתחילה בטביעת ספינה ומסתיימת בשלוש חתונות. ויולה נסחפת לחוף אילליריה, מתחפשת לגבר, ונסחפת למשולש אהבה מסובך ומשעשע.', 'ויולה עובדת אצל הדוכס אורסינו שמאוהב ברוזנת אוליביה, אבל ויולה מאוהבת בדוכס — ואוליביה מתאהבת דווקא בויולה המחופשת. שייקספיר במיטבו, עם בלבול זהויות, הומור ורומנטיקה. בגרסה נועזת של הבמאית רוני ברודצקי — לראשונה בישראל, רק נשים על הבמה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (55, 'קזבלן', 'קזבלן', 'תיאטרון הבימה', 100, 'המחזמר הישראלי המצליח בכל הזמנים. קזבלן, עולה ממרוקו, מתאהב בבתו של ראש השכונה, עולה מפולין שמתנגד לקשר בכל כוחו.', 'בשכונה מוזנחת ביפו מתנגשים עולמות — עדות, מעמדות ותרבויות על רקע ישראל של שנותיה הראשונות. הסיפור חושף מתחים עדתיים, פערים חברתיים ומאבק על קבלת האחר, בעטיפה מוזיקלית סוחפת. בשיתוף תיאטרון השעה הישראלי, הפקה צבעונית ומלאת אנרגיה שמהדהדת גם היום.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (56, 'מעגל הגיר הקווקזי', 'מעגל-הגיר-הקווקזי', 'תיאטרון הבימה', 160, 'הפקה מרהיבה המשלבת אמנות ציור בחול ומוזיקה מקורית סוחפת. יצירת המופת של ברטולט ברכט על גרושה, משרתת מטבח פשוטה שמצילה תינוק חסר ישע בזמן הפיכה אלימה.', 'כשהשליטים נמלטים ומותירים אחריהם תינוק, גרושה לוקחת אותו ובורחת. כשאם הילד חוזרת לתבוע אותו, השופט אזדאק צריך להכריע: למי שייך הילד — לאם שילדה אותו או לאישה שהצילה אותו? משל עוצמתי על צדק, הורות ומוסר שנותן לקהל לשפוט בעצמו.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (57, 'מלאכים בלבן', 'מלאכים-בלבן', 'תיאטרון הבימה', 90, 'ד"ר אלכס גולד, מתמחה בבית חולים, מתמודדת עם התאבדות בעלה שעמד בראש יחידת הפריון. בהיריון ונחושה, היא יוצאת לחקירה בלתי מתפשרת.', 'מה שמתגלה הוא רשת של טיוח, שחיתות רפואית וסודות שמאיימים לזעזע את בית החולים מהיסוד. מותחן רפואי ישראלי מקורי המבוסס על עולמה של העיתונאית החוקרת גילית קוזבה. כל הדמויות בדיוניות, אבל המתח אמיתי לחלוטין.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (58, 'קיצור תהליכים', 'קיצור-תהליכים', 'תיאטרון הבימה', 90, 'הפסיכולוג ראובן קליין סובל מכשלי זיכרון. שלושה מטופלים חרדתיים המקושרים זה לזו נכנסים לחייו, והגבול בין מציאות לדמיון מיטשטש.', 'אישה עם התקפי חרדה, בן זוגה שעובד על רובוט יפני, ושכנה ששוכנעה שפורצים לה לדירה — כולם קשורים במרקם סמוי. קליין מאבד אחיזה במציאות, ועולמות המטופל והמטפל מתמזגים ומתעוותים. יצירה נועזת בהשראת תורת הכאוס, מכניקת מערכת השמש והארוקי מוראקמי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (59, 'רומי + ג׳ולייט', 'רומי-+-ג׳ולייט', 'תיאטרון הבימה', 110, 'עיבוד מודרני של רומיאו ויוליה מאת גארי אואן. רומי הוא אב חד-הורי שבקושי שורד, וג׳ולייט נלחמת על חלומה ללמוד באוניברסיטה.', 'שני צעירים מעולמות שונים לחלוטין חווים את הכוח המטלטל של אהבה ראשונה. אבל בצומת הדרכים, משפחתה של ג׳ולייט חוששת לעתידה לצד רומי. עיבוד רענן ומפתיע שמוציא את שייקספיר מהטירות לרחובות, ומוכיח שסיפור האהבה הגדול עדיין חי ובועט.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (60, 'סיפור הפרברים – המחזמר', 'סיפור-הפרברים-–-המחזמר', 'תיאטרון בית ליסין', 110, 'המחזמר האייקוני בגרסה חדשה ומרהיבה. סיפור אהבתם האסורה של טוני, צעיר אמריקאי, ומריה, אחותו של מנהיג הכנופיה הפורטוריקנית היריבה, על רקע מאבק דרמטי ברחובות ניו יורק. יצירת מופת של ברנשטיין וסונדהיים עם תזמורת חיה.', 'הגרסה המודרנית של "רומיאו ויוליה" — שתי כנופיות, שני עולמות, אהבה אחת בלתי אפשרית. טוני ומריה מתאהבים למרות העוינות בין הקבוצות, אך סיפור האהבה מתגלגל למאבק טרגי. שירי המחזמר הפכו לאבני דרך בתולדות מחזות הזמר, והיצירה זכתה לשני סרטים אייקוניים וזוכי אוסקר. עשרות שחקנים, זמרים, רקדנים ותזמורת חיה ב-50 הצגות בלבד.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (61, 'בחורים טובים', 'בחורים-טובים', 'תיאטרון בית ליסין', 90, 'כשמוטי ברנשטיין, בחור ישיבה אשכנזי, מתאהב בנחמי ביטון המרוקאית, הוא יודע שהשידוך לא יתקבל בברכה בקהילה החרדית בבני ברק. קומדיה רומנטית בקו התפר שבין גפילטע פיש לחריימה.', 'קומדיה רומנטית המבוססת על אחד מסרטי הקולנוע המצליחים ביותר בשנים האחרונות. כשמוטי ברנשטיין, בחור ישיבה אשכנזי, מתאהב בנחמי ביטון המרוקאית, הוא יודע שהשידוך הזה לא יתקבל בברכה בקרב הקהילה החרדית בבני ברק. סיפור אהבה בקו התפר שבין גפילטע פיש לחריימה. מאת אורן יעקובי, על פי סרטם של יקי רייסנר, ארז תדמור וחוה דיבון.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (62, 'לילה ברומא', 'לילה-ברומא', 'תיאטרון בית ליסין', 90, 'קומדיה מטורפת על לילה מטורף. זוג יהודי-ישראלי וזוג ערבי-ישראלי מוצאים את עצמם בחדר אחד בבית מלון נידח ברומא, לאחר שטיסתם נדחתה בגלל אירוע ביטחוני.', 'המחזאי רמי ורד והבמאי אילן רונן מציבים מראה מול החולשות והחוזקות של הישראלים, בני כל הלאומים. מה קורה כשזוג יהודי-ישראלי וזוג ערבי-ישראלי מוצאים את עצמם ללילה אחד, בחדר אחד, בבית מלון נידח ברומא, לאחר שטיסתם ארצה נדחתה בגלל אירוע ביטחוני? קומדיה סאטירית חדה ומצחיקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (63, 'בין קודש לחולון', 'בין-קודש-לחולון', 'תיאטרון בית ליסין', 90, 'יהודה וייס, איש עסקים מצליח, מנהל חיים כפולים — חי עם בת זוגו החילונית בחולון, אך בימים שבהם הוא "טס לבלגיה" הוא נוסע לירושלים אל משפחתו החרדית.', 'כשבתו החילונית יעל מודיעה שהתאהבה בצעיר חרדי, התחפושת הכפולה מתחילה לחנוק. לאחר ההצלחה הגדולה של "ארבע אימהות", המחזאי דניאל לפין והבמאי אילן רונן חוזרים עם קומדיה מטורפת ומעוררת מחשבה על דת, חילון והזהות הישראלית.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (64, 'אמדאוס', 'אמדאוס', 'תיאטרון בית ליסין', 110, 'דרמה מרתקת על יצרים, תככים וקנאת יוצרים. מאבק בלתי מתפשר בין מוצרט, מלחין צעיר וכריזמטי, לסליירי, מלחין החצר הוותיק והמכובד. 50 הצגות בלבד.', 'מחזהו הנודע של פיטר שאפר כבש את במות התיאטרון בעולם והפך לסרט קולנוע אייקוני וזוכה פרסי האוסקר. המחזה עולה בגרסה עדכנית, פרועה וצבעונית, בתרגום ועריכה מוזיקלית של דורי פרנס ובבימויו של רוני ברודצקי. דרמה מרתקת על מאבק בלתי מתפשר בין וולפגנג אמדאוס מוצרט, מלחין צעיר, כריזמטי וחסר רסן, לאנטוניו סליירי, מלחין החצר הוותיק והמכובד.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (65, 'דתילונים', 'דתילונים', 'תיאטרון בית ליסין', 90, 'דפנה ואביחי הם זוג תל-אביבי צעיר. כשאביחי מציע לדפנה להתחתן, הוא מתחיל להניח תפילין ומבקש שלא לנסוע בשבת. קומדיה רומנטית על דו-קיום בין אמונה לתשוקה.', 'היא מפיקת אירועים ומסיבות, הוא מוזיקאי מצליח. כשאביחי מציע לדפנה להתחתן, הוא מתחיל להניח תפילין ומבקש שלא לנסוע בשבת. קומדיה רומנטית צעירה ומעוררת הזדהות — לא דתיים ולא חילוניים: דתילונים. המחזה פותח בביה"ס למחזאות של תיאטרון בית ליסין, מאת טל אידיסיס וטל צ''רנובסקי, בבימוי עידו רוזנברג.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (66, 'קרנפים', 'קרנפים', 'תיאטרון בית ליסין', 105, 'מחזהו הקלאסי הנודע של אז''ן יונסקו בגרסה עדכנית ונועזת. עדר מסתורי של קרנפים תוקף עיירה שלווה, וגיבור המחזה מנסה לשמור על חבריו ואהובתו מפני הצטרפותם לעדר. 50 הצגות בלבד.', 'המשל הנודע של יונסקו מקבל משמעות רלוונטית נוכח המציאות של ימינו. בראנז''ה, גיבור המחזה, מנסה לשמור על חבריו ואהובתו מפני הצטרפותם לעדר הקרנפים. בעיבוד לעברית של אלי ביז''אווי ובפרשנותו של יאיר שרמן, במאי הבית של תיאטרון בית ליסין, שביים את "המלט", "הדה גאבלר" ו"אנטיגונה".') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (67, 'אפס ביחסי אנוש', 'אפס-ביחסי-אנוש', 'תיאטרון בית ליסין', 100, 'לראשונה על הבמה — קומדיה מוזיקלית מרגשת על שלוש חיילות במשרד שלישות בבסיס צבאי נידח. מבוסס על אחד הסרטים המצליחים ביותר שנוצרו בישראל.', 'קומדיה מוזיקלית מבוססת על סרטה של טליה לביא. דפי המפונקת, זוהר הקיבוצניקית ורמה הקצינה מבינות שהדרך היחידה לנצח במלחמות שלהן בתוך מסגרת היררכית, נוקשה וגברית, היא בעזרת אחוות לוחמות. מאת אורן יעקובי, בבימוי עידו רוזנברג, מוזיקה מאת עילי בוטנר. קומדיה מפתיעה ומרעננת על התבגרות, חברות ומימוש עצמי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (68, 'אור לגויים', 'אור-לגויים', 'תיאטרון בית ליסין', 90, 'קומדיה חדשה על אובדן זהות. לאחר פטירת אמו, מתברר לאור אאוסלנדר, מורה לספרות, שהיא לא הייתה יהודייה. מה שמתפרש כטעות בירוקרטית הופך לעובדה שמערערת את חייו.', 'אור יוצא למסע מוטרף שמתחיל בפקיד של רבנות ומגיע לשיאו בסיאנס עם רוחה של אמו כדי לגבש לעצמו את זהותו האמיתית. קומדיה מטורפת חדשה פרי עטו של דניאל לפין ("ארבע אימהות", "בין קודש לחולון", "זהו זה"), על משבר הזהות הכי לא צפוי. בבימוי תמר קינן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (69, 'הכל אודות איב', 'הכל-אודות-איב', 'תיאטרון בית ליסין', 105, 'דרמה מרתקת על תהילה וקנאה. מרגו קריין, כוכבת תיאטרון מפורסמת, מכניסה לחייה עוזרת אישית צעירה בשם איב — מעריצה שרוצה לגעת בתהילה. עיבוד בימתי לסרט הקלאסי זוכה 6 פרסי אוסקר.', 'איב מתגלה כחרוצה, נאמנה ופעלתנית, אבל לאט-לאט מרגו מגלה סתירות ושקרים בסיפור חייה. כשערב אחד איב קופצת בספונטניות להחליף את מרגו על הבמה, מתפתח מאבק מלא יצרים, קנאה וסודות על מעמד והצלחה. מאת מרי אור, בעיבוד לעברית של דורי פרנס, בבימוי רוני ברודצקי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (70, 'קיר זכוכית', 'קיר-זכוכית', 'תיאטרון בית ליסין', 110, 'חיה, רקדנית ישראלית צעירה, התחילה חיים חדשים בברלין עם קריירה מצליחה והריון סודי. בפתח תקווה נשארו אחיה ואמה, שמסרבת לדבר איתה כבר שנתיים.', 'כשויקי, אמה של חיה, מגיעה לברלין כדי לממש את הצוואה הלא שגרתית של אביה, בני המשפחה נכנסים לסחרור שחושף בהרבה הומור וכאב את העבר שלהם ואת זה של היהודים בגרמניה. קומדיה דרמטית על הדור השני, הדור השלישי ומה שנשאר מהדור הראשון. מאת אורן יעקובי, בבימוי אלדר גוהר גרויסמן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (71, 'אף מילה לאמא', 'אף-מילה-לאמא', 'תיאטרון בית ליסין', 100, 'כשנורית מגלה שבעלה בוגד בה, היא מזמינה את בעלה של המאהבת ודורשת ממנו לצאת למלחמה על כבודם. קומדיה אנטי-רומנטית מצחיקה עד דמעות.', 'במקום הזוג הבוגד, מגיעים למקום המפגש בתה המתבגרת של נורית ובחור מבולבל, לליל האהבה הראשון שלהם. כשהבעל הבוגד מגיע לבסוף עם המאהבת שלו, המפגש יוצא מכלל איזון והופך לקומדיה מטורפת של טעויות. מאת נעם גיל, בבימוי אודי גוטשלק.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (72, 'חנאל ומכבית', 'חנאל-ומכבית', 'תיאטרון בית ליסין', 110, 'מכבית, מורה ויועצת באולפנה שהתגרשה מחנאל אב הבית, מגלה שהוא יוצא עם בת השירות. קומדיה בהשגחה פרטית, משעשעת עד דמעות.', 'מכבית מציבה בפני חנאל אולטימטום: לעזוב את בת השירות או את האולפנה. בינתיים, חברה לחדר המורים פותחת עבורה עמוד באפליקציית היכרויות, וחייה החדשים מוציאים את חנאל מדעתו. האם איחוד מחדש יפתור את התסבוכת? מאת חן רוטמן ואושרית סרוסי, בבימוי אודי גוטשלק.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (73, 'מלכת היופי של ירושלים', 'מלכת-היופי-של-ירושלים', 'תיאטרון בית ליסין', 100, 'בכורה עולמית. עיבוד בימתי מסעיר ומרגש לרב המכר הנמכר ביותר בישראל. דרמה רומנטית המתרחשת ערב קום המדינה, סיפורה של לונה, מלכת היופי של ירושלים.', 'לונה, בת למשפחה ירושלמית ספרדית, מתאהבת בדוד האשכנזי שחזר משירות צבאי בבריגדה היהודית באירופה. היא נישאת לו למרות התנגדותן של אמה וסבתה, ומתפכחת כשהיא מגלה שאמיתות החיים רחוקות מדמיונות הנעורים. מבוסס על ספרה של שרית ישי-לוי, מאת ליאת פישמן לני ושלומית ארנון בר-לב, בבימוי אודי גוטשלק.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (74, 'משחקים בחצר האחורית', 'משחקים-בחצר-האחורית', 'תיאטרון בית ליסין', 75, 'קבוצת נערים מזמינה נערה למשחקים אסורים בגן שבקצה הקיבוץ. הדינמיקה הקבוצתית הופכת את מפגש הנעורים לזירה של השפלה. קלאסיקה ישראלית מכוננת.', 'במרכז המחזה של עדנה מזי"א מתקיים משפט האונס, שבו דמות הקורבן הופכת לתובעת והנערים נאלצים להגן על עצמם. המחזה מבוסס על פרשת האונס בקיבוץ שמרת, שזעזעה את מדינת ישראל ושינתה את דפוסי הדיון הפליליים והמוסריים. בבימוי עידו רוזנברג, חוזר לבמה בגרסה חדשנית ומרתקת.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (75, 'שם פרטי', 'שם-פרטי', 'תיאטרון חיפה', 110, 'קומדיה צרפתית מאת מתיא דלאפור ואלכסנדר דה לה פאטאלייר. מה קורה כשגיבור הקומדיה מחליט לקרוא לבן שלו אדולף? ערב משפחתי שהולך בכיוון עקום לחלוטין.', 'זה היה אמור להיות ערב פריזאי נעים וחביב בבית, עם משפחה וחברים. רק שהכל הולך כמובן בכיוון עקום לחלוטין, ואף אחד מן הנוכחים לא ישכח את הערב המופרע הזה. זה מתחיל במשחק שעורך וונסן, האבא-לעתיד, ובו מתבקשים הכל לנחש את השם הפרטי שבחר לרך שיוולד. מה קורה כשגיבור הקומדיה מחליט לקרוא לבן שלו אדולף?... ההפקה בשיתוף תיאטרון השעה הישראלי. בימוי: מורדי גרשון. בהשתתפות: גלית גיאת, בן פרי, אמיר קריאף, ירדן ברכה, יואב בר לב.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (76, 'חנה לסלאו היא ד"ר רות ווסטהיימר', 'חנה-לסלאו-היא-ד-ר-רות-ווסטהיימר', 'תיאטרון חיפה', 75, 'מחזה מאת מארק סן-ג׳רמיין המבוסס על חייה של ד״ר רות ווסטהיימר, המטפלת המינית המוכרת והאהובה ביותר בעולם. הצגת יחיד מרגשת ומלאת הומור.', 'ד״ר רות ווסטהיימר מוכרת לעולם כזקנה קטנטנה וחייכנית שמדברת ללא עכבות על סקס. היא שינתה את הדרך בה אנו מדברים על סקס והפכה למטפלת המינית המוכרת והאהובה ביותר בעולם. מה שהעולם לא יודע - זה שהיא נולדה כקרולה סיגל, ועל מנת להפוך לד״ר רות, היא עברה מסע ניצחון בלתי רגיל. כעת, היא מכניסה אותנו אל ביתה כדי לחלוק איתנו את המסע הזה. באמצעות החום, האופטימיות וכמובן עם ההומור המפורסם שלה, ד״ר רות עוברת עם הקהל דרך כל תחנות חייה - הבריחה מגרמניה הנאצית, התבגרותה בפנימייה בשוויץ, הכשרתה כצלפת ישראלית בשנות ה-40, חייה כאם יחידנית באמריקה, ולבסוף - הפיכתה לסלבריטאית בינלאומית. בימוי: תמר קינן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (77, 'המאסטר (אלוף הבונים שלי)', 'המאסטר-(אלוף-הבונים-שלי)', 'תיאטרון חיפה', 90, 'עיבוד מודרני ליצירה הקלאסית מאת הנריק איבסן. מה שנראה כאיחוד מלהיב מתנפץ עם הגעתה הבלתי צפויה של תלמידה לשעבר.', 'בערב ה-4 ביולי, בהמפטונס, אלנה סולנס, מו"לית מוערכת מאד, מתכוננת לערוך מסיבה לכבוד בעלה האדריכל, הנרי סולנס, בזמן שהוא חושף את יצירת המופת האחרונה שלו. מה שנראה לכאורה כאיחוד מלהיב מתנפץ עם הגעתה הבלתי צפויה של מתילד, תלמידה לשעבר של הנרי, איתה ניהל בעבר קשר אינטימי. ככל שהערב מתגלגל, כל אחד מהם מוצא את עצמו מול אמת שתשנה את ציר חייהם. עיבוד מודרני מטלטל ליצירה הקלאסית מאת איבסן. מאת ליילה ראיסק. בימוי: שיר גולדברג. בהשתתפות: יפתח קליין, יעל שרוני, גל אמיתי, יובל שרף, סתיו זוהר דהן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (78, 'לשחרר את נחמה', 'לשחרר-את-נחמה', 'תיאטרון חיפה', 90, 'קומדיה ישראלית מקורית מאת דניאל לפין. ארבע נשים מאושפזות מתקשות לישון בגלל אישה חמישית שמרעישה בלילות. יצירה סוריאליסטית, חדה, מרגשת ומצחיקה.', 'ארבע נשים, המאושפזות במחלקה פנימית בבית חולים, מתקשות לישון כי אישה חמישית, נחמה כהן, מרעישה בלילות. כאשר אובדים הסיכויים להעביר את נחמה חדר, אחת הנשים מעלה דרך תיאורטית לשחרר את הבעיה... לאחר דיון מוסרי סוער ומלא יצרים, הארבע נרדמות וקמות בבוקר לבשורה מפתיעה... יצירה סוריאליסטית, חדה, מרגשת ומצחיקה עד כאב, שמצליחה לשלב קומדיה שחורה עם תובנות חברתיות מדויקות. מאת דניאל לפין. בימוי: משה נאור. בהשתתפות: ציפי שביט, עידן אלתרמן, שלמה וישינסקי, עירית ענבי, נועה אנגל, מעין וינשטוק, קובי זיסלין.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (79, 'משתגעים מאהבה', 'משתגעים-מאהבה', 'תיאטרון חיפה', 100, 'מחזמר - קומדיה מוזיקלית על מסע ומשא האהבה. ארבעה שחקנים וירטואוזים מחליפים דמויות ותפקידים ויוצרים פסיפס אנושי עשיר.', 'המחזמר המצליח ״משתגעים מאהבה״ הוא קומדיה מוזיקלית על מסע - ומשא - האהבה. ארבעה שחקנים וירטואוזים מחליפים דמויות ותפקידים, ויוצרים פסיפס אנושי עשיר - מהדייטים המביכים של תחילת הדרך ועד נישואין, הורות, משברים, ואהבות חדשות בגיל השלישי. בשפה תיאטרונית דינמית ושירים מלאי הומור ורגש, ההצגה מציעה מבט חד, שנון ולרגעים גם מרגש עד דמעות על הצורך של כולנו לאהוב ולהיות נאהבים. מחזה ופזמונים ג׳ו דיפייטריו, מוזיקה ג''יימי רוברטס. בימוי: גמא פריד. בהשתתפות: בן פרי, דיאנה גולבי, עידו מוסרי, איילת רובינסון.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (80, 'לילסדה', 'לילסדה', 'תיאטרון חיפה', 100, 'על פי סרטו של שמי זרחין. על רקע ארוחת ליל הסדר המשפחתית מתרחשות דרמות קטנות בחיי משפחה המתכנסת לקראת החג. גרסת בכורה בימתית לסרט עטור הפרסים.', 'על רקע ארוחת ליל הסדר המשפחתית מתרחשות דרמות קטנות בחיי משפחה המתכנסת בבית ההורים לקראת החג, ורק אחד חסר, יזהר, בן הזקונים שנהרג בפעילות צבאית. במשך יומיים מתערבבים סיפורי הדמויות זה בזה ויוצרים דרמה מסחררת של אהבה, בגידה, געגועים, כעסים, צחוק, דמעות, שירים והרבה מאוד אוכל. זוהי גרסת בכורה בימתית לסרט עטור הפרסים, מאת הצוות שהביא אל הבמה בעונה החולפת את הלהיט ״אביבה אהובתי״. עיבוד לבמה: ארז דריגס. בימוי: משה קפטן. בהשתתפות: אוולין הגואל, אריה צ׳רנר, תקווה עזיז, נינה קוטלר, זהר שטראוס, עדנה בליליוס, הילה סעדה, נדיר אלדד, בר ברימר, לירי הפנר, דניאל גימפל.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (81, 'הזוג המוזר', 'הזוג-המוזר', 'תיאטרון חיפה', 90, 'קומדיה מאת ניל סיימון. פליקס הנוירוטי עובר לגור עם חברו אוסקר הגרוש המרושל. הצמד הקומי המבריק גרייניק ואלתרמן בגרסה ישראלית חדשה.', 'פליקס (עידן אלתרמן), טיפוס נוירוטי ואובססיבי לסדר וניקיון, שאישתו זרקה אותו מביתו, עובר לגור עם חברו, אוסקר (אבי גרייניק), גרוש טרי מרושל ומבולגן. המפגש מלא הניגודים בין השניים יוצר קומדית מצבים קורעת מצחוק. הצמד הקומי המבריק, גרייניק ואלתרמן, מתאחדים שוב לגרסה ישראלית חדשה ומוטרפת של הקומדיה הקלאסית מאת ניל סיימון. בימוי: משה נאור. בהשתתפות: אבי גרייניק, עידן אלתרמן, מעין וינשטוק, נועה טסה, איתי פולישוק, אסף דגני, שי אגוזי, אייל שרף.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (82, 'היומן', 'היומן', 'תיאטרון חיפה', 100, 'מחזמר עטור שבחים הישר מברודווי, מבוסס על הרומן הנמכר ביותר שהיווה השראה לסרט האייקוני. סיפור אהבה יוצא דופן על כוחה המתמשך של האהבה.', 'מחזמר עטור שבחים, מבוסס על הרומן הנמכר ביותר שהיווה השראה לסרט האייקוני. אלי ונואה, שניהם מעולמות שונים, חולקים חיים שלמים של אהבה למרות הכוחות המאיימים לפרק אותם, בדיוקן מרגש מאוד של כוחה המתמשך של האהבה. סיפור אהבה יוצא דופן על המאבק להיזכר כמה אהבנו לאהוב. מאת אינגריד מייקלסון ורבקה ברנסטטר. בימוי: משה קפטן. בהשתתפות: גילה אלמגור, רוני דלומי, נועם קליינשטיין, דודו פישר, דפנה דקל, נדיר אלדד, עדן ביטון. בשיתוף NMC.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (83, 'מקומות שמורים', 'מקומות-שמורים', 'תיאטרון באר שבע', 90, 'דרמה קומית ישראלית על חנה, אלמנה דתיה בת 60, שמגלה שאישה מסתורית נקברה בחלקת הקבר שלה ויוצאת למסע לגלות את האמת.', 'כאשר חנה, אלמנה דתיה בת 60 מרמת גן, מגלה שבחלקת הקבר המיועדת לה לצד בעלה המנוח נקברה אישה מסתורית, היא נחושה לגלות מי האישה הזאת ולהחזיר לעצמה את המקום שתכננה לבלות בו את הנצח. הסיכוי היחיד שלה הוא עורך דין בדימוס, אלמן ערבי-נוצרי מיפו בשם חנא, שנכנס במקרה לחנות הצילום שלה ונעתר לסייע לה. יחד יוצאים חנה וחנא למסע שיגלה לשניהם שיש חיים אחרי המוות. מחזה מאת איתן ענר, בבימוי תמר קינן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (84, 'העלמה והמוות', 'העלמה-והמוות', 'תיאטרון באר שבע', 90, 'מחזה מתח סוחף על נקמה, צדק ופיוס בצ''ילה שלאחר הדיקטטורה. פאולינה מזהה את קולו של אורח ומשוכנעת שהוא האיש שחטף וחקר אותה לפני שנים.', 'המקום הוא בית נופש מבודד בצ''ילה. השנה היא 1990, מיד לאחר נפילת המשטר הדיקטטורי. בעלה של פאולינה מביא אתו אורח – רופא נדיב שסייע לו כשהרכב שלו נתקע. פאולינה מזהה את קולו: היא משוכנעת שזה האיש שחטף וחקר אותה לפני חמש עשרה שנה כשהייתה מתנגדת משטר. אבל אולי פאולינה טועה? הרי היא מעולם לא ראתה את פניו. מחזה מאת אריאל דורפמן, זוכה פרס לורנס אוליביה למחזה החדש הטוב ביותר 1992. בבימוי אמיר י. וולף.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (85, 'יעקובי ולידנטל', 'יעקובי-ולידנטל', 'תיאטרון החאן', 100, 'קלאסיקה של חנוך לוין על שני חברים ותיקים שחברותם מתפרקת כשאחד מהם יוצא לחפש את האושר, ועל המשולש העגום שנוצר עם פסנתרנית בודדה.', 'איתמר יעקובי ודוד לידנטל, שני חברים ותיקים, שקעו במשך שנים בחיי נוחות קטנים: דג מלוח, תה דלוח ומשחקי לוח, כל ערב על אותה מרפסת. יום אחד קם יעקובי, הורס את החברות ויוצא החוצה כדי סוף סוף להתחיל ״לחיות״. בשיטוטיו הקדחתניים ברחובות הוא נתקל ברות שחש, פסנתרנית עם חיים קטנים וחלומות גדולים, וכך מסתבך המשולש העגום של יעקובי-שחש-לידנטל במאבק מגוחך ומכמיר לב על כבוד, על אהבה ועל אושר. מחזה עם פזמונים מאת חנוך לוין, בבימוי מעין אבן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (86, 'נער האופניים', 'נער-האופניים', 'תיאטרון החאן', 95, 'עיבוד חדש לספרו של אלי עמיר על נורי בן השש עשרה, יליד בגדאד, שנשלח לבדו לירושלים בשנות החמישים ומנסה להתערות בארץ החדשה.', 'שנות החמישים של המאה הקודמת. נורי בן השש עשרה, יליד בגדאד, נשלח לבדו במצוות אביו אל ירושלים כדי להשיג למשפחה דירת שיכון בעיר הבירה. הוא מתפרנס מחלוקת עיתונים ומשליחויות על אופניים במשרד ראש הממשלה, ומנסה להתערות בארץ החדשה תוך שהוא חולם על חיים אחרים. עיבוד חדש מאת איה קפלן על פי הרומן מאת אלי עמיר, בבכורה ישראלית. בימוי: איה קפלן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (87, 'הסבתות', 'הסבתות', 'תיאטרון החאן', 80, 'חמישה שחקנים מפיחים חיים בסבתות שלהם בהצגה שהיא מחווה לדור הוותיקים – קומדיה מרגשת, מצחיקה ומלאת שירים וריקודים.', 'חמישה משחקני החאן נכנסו לחדר החזרות ובתהליך יצירה מיוחד הפיחו חיים בימתיים בסבתות שלהם. התוצאה היא חבורת סבתות שגרות יחדיו בדיור מוגן, ולצידן אחות מוסמכת שמלווה אותן בשירה ובריקוד. הצגה שחושפת טפח מעולמם של הסבים והסבתות שלנו, ומאירה את יחסינו איתם באור כואב, מרגש, מצחיק ובעיקר מתגעגע. קומדיה בסגנון חופשי מאת שירילי דשא והשחקנים, בבימוי שירילי דשא.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (88, 'מחכים לגודו', 'מחכים-לגודו', 'תיאטרון החאן', 100, 'יצירת המופת של סמואל בקט על שני נוודים עייפים הממתינים לדמות מסתורית בשם גודו – בין ריק לתקווה, בין צחוק לאימה.', 'ולדימיר ואסטראגון, שני נוודים עייפים, אולי חברים, אולי רק שני אנשים שמנסים לשרוד, ממתינים ליד עץ. הם מחכים לדמות מסתורית בשם גודו שאולי תגיע, אולי לא. בתוך ההמתנה מתרחשים רגעים קטנים של חסד, בדיחות אבסורד, כאב שקט והומור מטורף. שיחות על נעליים, ירקות, זמן, משמעות; ובעיקר על האין-מוצא שממנו כולנו עשויים. מאת סמואל בקט, בבימוי אודי בן משה, נוסח עברי: יוסף אל-דרור.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (89, 'הכי בבית בעולם', 'הכי-בבית-בעולם', 'תיאטרון החאן', 80, 'קומדיה ישראלית חדשה – ארבעה סיפורים פרועים על ישראלים שנתקעים בשדות תעופה ברחבי העולם ומנסים בנואשות לשוב הביתה.', 'ליסבון, ורשה, דובאי ולרנקה. ארבעה סיפורים פרועים על ישראלים שנתקעים בשדות תעופה ברחבי העולם, בניסיון נואש לשוב הביתה. בשעה שהשמיים נסגרים ונפתחים בלי התראה מוקדמת, הם נלחמים אחד בשני ובעצמם, במטרה לחזור לקצת שפיות. קומדיה ישראלית חדשה מאת ובבימוי מתן דרעי בדש וטל בסון. הפקת מקור: סטודיו ניסן נתיב ירושלים.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (90, 'מי שסוכתו נופלת', 'מי-שסוכתו-נופלת', 'תיאטרון החאן', 90, 'עיבוד בימתי לרב המכר של צבי בן מאיר, על בנימין קמחי שמתחתן כדי למלא ציפיות חברתיות ודתיות, בעוד הוא מסתיר סוד גדול.', 'בנימין ״ביני״ קמחי, בן הרב שלמה ובוגר ישיבת הסדר, מתחתן עם אסתר היפה כדי למלא אחר הציפיות החברתיות והדתיות. הזוג בונה משפחה עם שני ילדים, אך החיים בצל סוד גדול יוצרים חיץ בלתי נראה ביניהם, והמציאות דורשת מהם להתעמת עם האמת. המחזה חושף את המתח שבין זהות אישית אותנטית לבין צו החברה, ואת האומץ הנדרש כדי לחיות בכנות גם במחיר של איבוד הסוכה המגוננת של הקהילה. עיבוד ובימוי: נועה שכטר, דרמטורגיה: ירון אדלשטיין.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (91, 'אם זה אדם', 'אם-זה-אדם', 'תיאטרון החאן', 60, 'ספרו של פרימו לוי ״הזהו אדם?״ המתאר את חוויותיו באושוויץ מעובד לתיאטרון לראשונה – מונולוג אינטימי ומרגש.', 'ספרו הידוע של פרימו לוי ״הזהו אדם?״ המתאר את חוויותיו באושוויץ, מעובד לתיאטרון לראשונה. ניר רון, מבכירי להקת שחקני החאן, מבצע את המונולוג באולם קטן ובקרבה אינטימית רבה אל הצופים. עיבוד ובימוי: מור פרנק, עברית: מירון רפופורט.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (92, 'דרייפוס', 'דרייפוס', 'תיאטרון החאן', 90, 'בעיירה יהודית בפולין בין שתי מלחמות העולם, להקת שחקנים חובבים עורכת חזרות על מחזה שמשחזר את פרשת דרייפוס. קומדיה מרגשת על יהדות, הישרדות ואהבת האומנות.', 'בעיירה יהודית בפולין, בין שתי מלחמות העולם, להקת שחקנים חובבים עורכת חזרות על מחזה המשחזר את פרשת דרייפוס. על רקע האנטישמיות המאפילה אט אט על חייהם, הם עסוקים בוויכוחים ובמריבות על כל פרט בהצגה: על צבע המדים, על איך משחקים והאם אירוע כמו פרשת דרייפוס עלול להתרחש שוב. מחזה מצחיק ונוגע ללב מאת ז׳אן קלוד גרימברג, בבימוי ארז שפריר, נוסח עברי: אלי ביז׳אווי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (93, 'הורים יקרים', 'הורים-יקרים', 'תיאטרון החאן', 90, 'השלאגר התיאטרוני הגדול מפריז בבכורה עברית – קומדיה על משפחה, אהבה וכסף, כשחדשות נפלאות של ההורים דווקא מזעזעות את כל התא המשפחתי.', 'פייר, ז׳ול ולואיז אוהבים אחד את השני ואוהבים את הוריהם אהבת נפש. כשההורים מבקשים מהם להגיע בבהילות כי יש להם משהו דחוף להגיד, שלושת הילדים המודאגים ממהרים להגיע וחוששים מן הרע מכל. אבל הרע מכל לא קורה, ודווקא החדשות הנפלאות שיש להורים לבשר לילדיהם הן אלה שמזעזעות את התא המשפחתי. קומדיה מאת עמנואל פטרון וארמל פטרון, בבימוי ארז שפריר, נוסח עברי: דורי פרנס.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (94, 'משרתם של שני אדונים', 'משרתם-של-שני-אדונים', 'תיאטרון החאן', 100, 'הקומדיה הקלאסית של גולדוני חוזרת לבמת החאן חמישים שנה אחרי ההפקה המיתולוגית, בתרגומו הגאוני של ניסים אלוני ובגרסה חדשה ופרועה.', 'חמישים שנה בדיוק לאחר שעלתה ההפקה המיתולוגית של ״משרתם של שני אדונים״ בתיאטרון החאן, הקומדיה הקלאסית שכתב גולדוני במאה ה-18 בהשראת מסורת הקומדיה דל׳ארטה עולה שוב על במת החאן. פנטלון תכנן לחתן את בתו קלאריסה עם רספוני, אך לאחר ששמע שרספוני מת הסכים שבתו תתחתן עם אהוב ליבה סילביו. אז נכנס טרופלדינו, המשרת שמנסה ללהטט בין שני אדונים ומסבך את כולם בקומדיית טעויות פרועה. קומדיה מאת קרלו גולדוני, נוסח עברי: ניסים אלוני, עיבוד ובימוי: אריאל נ. וולף.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (95, 'מיתה טובה', 'מיתה-טובה', 'תיאטרון החאן', 100, 'קומדיה עצובה על חבורת דיירים בדיור מוגן שבונים מכונה להמתת חסד עצמית למען חברם החולה, אך העסק משתבש כשעוד ועוד קשישים באים לבקש ״מיתה טובה״.', 'חבורת דיירים בדיור המוגן ״נווה הרים״ נקלעת לבעיה: חברם הטוב מאובחן כחולה סופני ומבקש מהם לעזור לו לסיים את חייו ללא סבל. בגיוס כל המוחות החריפים שסביבם הם מצליחים לבנות מכונה להמתת חסד עצמית, ומגשימים את משאלתו. אך העסק משתבש כאשר עוד ועוד קשישים שומעים על המכונה המדוברת ובאים לבקש גם לעצמם ״מיתה טובה״. קומדיה עצובה על חברות ופרידה ועל הקו הדק שבין מוסר לאהבה. על פי סרטם של טל גרניט ושרון מימון, עיבוד לבמה: שלומית ארנון ויואב בר לב, בימוי: אודי בן משה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (96, 'נשמות', 'נשמות', 'תיאטרון גשר', 150, 'סיפורן של שתי נשמות בודדות, אלגוריה לסיפורו של עם שנע ונד בין חיים למוות בחיפוש אחר תיקון. גרישה מיפו נולד ומת שוב ושוב כבר ארבע-מאות שנה, מדלג ממאה למאה בחיפוש אחר נשמתו התאומה.', 'סיפורן של שתי נשמות בודדות, שהוא אלגוריה לסיפורו של עם שנע ונד בין חיים למוות, בחיפוש אחר תיקון. בגלגול הזה, גרישה גר עם אמא שלו ביפו, אבל נשמתו משוטטת בעולם כבר ארבע-מאות שנה. הוא נולד במאה ה-17 בעיירה יהודית ומאז הוא מת ונולד מחדש, מדלג ממאה למאה, מארץ לארץ, מגוף אל גוף. מה מגלגל אותו בחזרה אל האדמה – חטא בלתי נסלח או אהבה עצומה לנשמתו התאומה? על פי ספרו של רועי חן. בימוי: איתי טיראן. בהשתתפות: יבגניה דודינה, אריאל ברונז, נטע רוט, גלעד קלטר, עלא דקה, איה זמיר.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (97, 'סלומה', 'סלומה', 'תיאטרון גשר', 100, 'הפקה משותפת עם תיאטרון Royal Haymarket מלונדון. המלך הורדוס כולא את יוחנן המטביל, ואשתו שולחת את בתה סלומה לפתות אותו בריקוד שבעת הצעיפים במחזה הקלאסי של אוסקר ווילד.', 'הפקה משותפת עם תיאטרון Royal Haymarket מהווסט אנד בלונדון. סלומה הוא מחזה שעורר שערורייה במאה ה-19, הפך לקלאסיקה וזכה לעיבודים רבים. המלך הורדוס אנטיפס נושא לאישה את אשת אחיו, הרודיאה, דבר שאינו מקובל ביהדות ולכן מעורר עליו את חמתו של יוחנן המטביל. כדי להשתיק את יוחנן משליך אותו הורדוס לצינוק. אשתו שולחת את בתה, סלומה, לפתות את הורדוס ולרקוד לפניו את ריקוד שבעת הצעיפים. ההצגה בשפה האנגלית עם כתוביות בעברית ורוסית. מאת אוסקר ווילד. בימוי: מקסים דידנקו. בהשתתפות: דורון תבורי, מיכל ויינברג, נטע רוט, שיר סייג.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (98, 'החטא ועונשו', 'החטא-ועונשו', 'תיאטרון גשר', 100, 'קברט של תשוקות וייסורים על פי הרומן של דוסטויבסקי. הבמאי מולוצ׳ניקוב מכניס את הקהל לקרנבל תוסס שבו הגיבורים הקלאסיים מקבלים נימה מודרנית ומפתיעה.', 'קברט של תשוקות וייסורים. הבמאי אלכסנדר מולוצ׳ניקוב מכניס את הקהל למופע קברט, קרנבל תוסס שבו קולותיהם של הגיבורים הקלאסיים מקבלים נימה מודרנית ומפתיעה. דוסטוייבסקי, גאון המותחן הפסיכולוגי, מזמין אותנו למבוך הסבוך של המודע והתת-מודע האנושי. ברומן ״החטא ועונשו״ הוא חוקר את תהומות נשמתו של הפושע. על פי הרומן מאת פיודור דוסטויבסקי. עיבוד ובימוי: אלכסנדר מולוצ׳ניקוב. בהשתתפות: אבי אזולאי, גלעד קלטר, נטע רוט, נטשה מנור, סבטלנה דמידוב.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (99, 'סביצ׳ה', 'סביצ׳ה', 'צוותא', 75, 'מה קורה לאלונה בערב בו חיי הנישואים שלה מתפרקים? פיית שיניים מגיעה להגשים לה משאלה – להפוך אותה לבת ים. קומדיה בין נונסנס לאמירות פמיניסטיות.', 'מה קורה לאלונה בערב בו חיי הנישואים שלה מתפרקים? מגיעה לביתה פיית שיניים כדי להגשים לה משאלה שלא הספיקה – להפוך אותה לבת ים. קומדיה הנעה בין נונסנס וסלפסטיק לאמירות חברתיות, פוליטיות ופמיניסטיות. מאת אור ישראלי. בימוי: אלה ניקוליבסקי. בהשתתפות: ליליאן ברטו, יעל לבנטל, עידן אלתרמן, ליאור אביבי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (100, 'שושי בחלל', 'שושי-בחלל', 'צוותא', 75, 'שושי מחדרה לוקחת אוטובוס לתור אצל הגסטרו אבל מוצאת את עצמה בחלל החיצון. קומדיית נונסנס על אהבה, חברות ומסוף חדרה.', 'יום בהיר אחד, בחדרה הרחוקה, שושי לוקחת אוטובוס כדי להגיע לתור שלה לגסטרו – אבל מוצאת את עצמה בחלל החיצון. האם חברתה מרגלית תצליח להציל אותה לפני שיהיה מאוחר מדי? קומדיית נונסנס על אהבה, חברות ומסוף חדרה. מאת בן קורן ועומר אביטוב. בימוי: תמר פור. בהשתתפות: מיקה זק, זיו תשובה, ירדן בר-אל, אביב בן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (101, 'אנטי אייג׳ינג', 'אנטי-אייג׳ינג', 'צוותא', 75, 'לוסי, סטודנטית צעירה למשחק, מתאהבת בבועז לוי, שחקן מבוגר ומפורסם, ופולשת לחייו בחולון. קומדיה רומנטית עם שירים, זוכת פרסי הקומדיה הישראלי 2024.', 'לוסי, סטודנטית צעירה וחוצפנית למשחק, מגיעה לבכורה בתיאטרון הרמז. מהקהל היא קולטת את בועז לוי, שחקן מבוגר ומפורסם, שלמרבה ההפתעה לא משקיע ולא מדבר במבטא של השחקנות. בתחבולות היא גורמת לו להתחיל איתה, ובאישון לילה כבר עושה את דרכה לביתו שבעיר היונים חולון. קומדיה גם רומנטית, עם שירים. זוכת פרסי המחזה והשחקנית הטובים ביותר בפסטיבל הקומדיה הישראלי 2024. מאת מיכל לוסי גורפיין ויונתן בלומנפלד. בימוי: יונתן בלומנפלד. בהשתתפות: מיכל לוסי גורפיין, גל ברק, יונתן בלומנפלד, אתי וקנין-סוברי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (102, 'משחקי נישואים', 'משחקי-נישואים', 'צוותא', 60, 'איש ואישה בגיל העמידה נתקעים אחרי עשרים שנה במבוי יחסים ההולך ונסגר. דרמה קומית על פי אדוארד אולבי, על תעתועי הנישואים.', 'איש ואישה בגיל העמידה, שכמקובל היו זרים זה לזו כאשר התאהבו, נתקעים אחרי למעלה מעשרים שנה וילדים במבוי יחסים ההולך ונסגר. הם מנסים להבין מה הביא אותם לנפילה ההרסנית המשבשת את חייהם. אדוארד אלבי, המחזאי האמריקאי הגאוני (״מי מפחד מוירגיניה וולף״), עוסק בתעתועי הנישואים. על פי אדוארד אולבי. עיבוד ובימוי: עודד קוטלר. בהשתתפות: דניאל זהבי, לילך צור.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (103, 'בת של אבא', 'בת-של-אבא', 'תמונע', 60, 'נטע שפיגלמן, שחקנית מוערכת, מספרת על חמישה חודשים בהם ליוותה את אביה העיתונאי המיתולוגי במחלקה האונקולוגית – הפרק המתוק ביותר ביחסים שלהם.', 'אבא של נטע שפיגלמן היה עיתונאי מיתולוגי בערוץ הראשון. לוחם צדק שראה בתפקידו שליחות. נטע גדלה להיות שחקנית מוערכת. ובכל זאת, תפקיד חייה היה דווקא נטול קהל. במשך חמישה חודשים היא ליוותה את אבא שלה במחלקה האונקולוגית – מה שהיה לפרק המתוק ביותר ביחסים שלהם. עבודה תיאטרלית רב-ערוצית ומכתב אהבה לאבא שאינו. הפקת מקור של אנסמבל תמונע בשיתוף עם פסטיבל ישראל. יצירה ובימוי: נטע שפיגלמן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (104, 'רצח במועדון הטרנספר', 'רצח-במועדון-הטרנספר', 'תמונע', 80, 'אדם חמוש מתפרץ למועדון טרנסיות מחתרתי בירושלים ורוצח שלוש טרנסיות. שש שנים מאוחר יותר, ראיה חדשה פותחת מחדש את תיק החקירה בהצגה ייחודית מתוך חדר חקירות.', 'אדם חבוש כובע גרב וחמוש באקדח, מתפרץ לתוך מועדון טרנסיות מחתרתי בירושלים, רוצח שלוש טרנסיות ופוצע נוספים. שש שנים מאוחר יותר, כשזהות הרוצח עדיין לא ידועה, מתגלה ראיה חדשה שפותחת מחדש את תיק החקירה. הצגה ייחודית וראשונה מסוגה, המכניסה את הקהל למשחק המוחות הפסיכולוגי המתנהל בתוך חדר החקירות. זוכת פרס דעטרון 2023 להצגת פרינג׳ השנה. מאת מתן בן עמי ורם גואטה. בימוי: רם גואטה. בהשתתפות: מתן בן עמי, רם גואטה, שחף קהלני, יוני גבורה, יותם רוטשטיין.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (105, 'פריקואל וסיקואל יורשים כת', 'פריקואל-וסיקואל-יורשים-כת', 'תמונע', 75, 'קומדיה אפלה על שני אחים שמנסים למנוע מכת מסתורית להתפרק אחרי מות מנהיגתה, ומגלים צוות דוקו שהסתנן לצלם עליהם סרט תיעודי.', 'קומדיה אפלה על אנשים מוארים. כשהמנהיגה בת האלמוות של כת מסתורית בדרום הארץ מתה ערב אחד בפתאומיות, שני הבנים שלה, פריקואל וסיקואל, מנסים למנוע מהקהילה המיותמת להתפרק. כשהם מגלים צוות דוקו שהסתנן אל הכת כדי לצלם עליה סרט תיעודי, כל מה שהם יודעים על עצמם ועל העולם משתנה. בכורה במסגרת פסטיבל הקומדיה ע״ש אפרים קישון. מאת ובימוי: בן סגרסקי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (106, 'דיק פיק', 'דיק-פיק', 'תמונע', 60, 'הצגה העוסקת בפירוק והרכבה של מושג הגבריות הישראלית, דרך תמונות מחייהם של שמונה גברים צעירים מילדות עד בגרות.', 'ההצגה עוסקת בפירוק והרכבה של מושג הגבריות הישראלית. דרך מסע אסוציאטיבי נפרשות תמונות מחייהם של שמונה גברים צעירים, מילדות עד בגרות, בשילוב פסקול, קטעי תנועה והקלטות אינטימיות. חוויה תיאטרונית כנה, מרגשת ומלאת הומור שמזמינה את הקהל להתבונן מחדש במורכבות של גבריות בארץ. מאת ובימוי: נעה וגנר וצוות השחקנים.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (107, 'בית בעזה', 'בית-בעזה', 'תמונע', 60, 'פרפורמנס חפצים על הימים הראשונים במלחמה. דניאל משתמש בחפצים שמצא בבית בג׳בליה כדי להבין מה קרה לו ולחבריו במלחמה.', 'פרפורמנס חפצים על הימים הראשונים במלחמה. באחד מהבתים בג׳בליה, המפקד אסף את הצוות לתדריך סביב שולחן במטבח. הוא השתמש בחפצים שמצא כדי להסביר מה קורה. דניאל לא הצליח להתרכז בתדריך כי הוא דמיין איך השולחן הזה – וגם קופסת גפרורים, בלון, סרגל מתכת, כפכף, נעל בלט – הופך למופע, שיעזור לו להבין מה קרה לו, לחבריו, לקהל – במלחמה. יצירה וביצוע: דניאל אנגל. בימוי ודרמטורגיה: יונתן לוי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (108, 'אבא יצא מהקבוצה', 'אבא-יצא-מהקבוצה', 'תמונע', 65, 'יוצר תיאטרון בן חמישים שובר את הכלים ומחליט לתת לעצמו צ׳אנס לחיים חדשים – אבא יותר טוב, יוצר מוצלח יותר, ואפילו גרוש מוצלח יותר. טרגדיה קומית לפחות כמו החיים.', 'יוצר תיאטרון בן חמישים יודע שהחיים קצרים וכרגע זה ממש לא זה. אשתו אוהבת אותו פחות, הוא מצליח רק בשוליים, ואימא שלו עם אלצהיימר במוסד. הוא שובר את הכלים ומחליט לתת לעצמו צ׳אנס לחיים חדשים. הוא מנסה להיות אבא יותר טוב, יוצר יותר מוצלח, ואפילו גרוש מוצלח יותר. טרגדיה קומית לפחות כמו החיים. מאת ובימוי: אלירן כספי ואמיר פתר. בהשתתפות: אלירן כספי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (109, 'האוויר הוא של כולם', 'האוויר-הוא-של-כולם', 'תמונע', 50, 'שני אחים בני 20 ומשהו מנסים לחזור לגור ביחד במחשבה שזה יהיה כמו פעם, אבל החלום מחזיר אותם לפחדים ולהתמודדויות עד פיצוץ.', 'שני אחים, שני מזרונים וכדור. האחים ישורון כשהם בני 20 ומשהו רוצים לחזור לגור ביחד במחשבה שזה יהיה כמו פעם. דבר שהתחיל כחלום לחזור לילדות מחזיר אותם לפחדים והתמודדויות עד פיצוץ החוזה והחלום. תוך משחקים, זריקת מזרנים, מכות וג׳ימי הנדריקס נחשף הפער והשוני בין שני האחים. יצירה ומשחק: ירדן ישורון והראל מרקו ישורון. בימוי: הראל מרקו ישורון.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (110, 'השתקפויות', 'השתקפויות', 'תמונע', 70, 'מחזה מצחיק ושנון על דניאל וקרין, זוג במשבר נישואין עם פער ערכי עמוק. אבל האם הם דמויות אמיתיות, או מראות של יוצר תיאטרון המנסה לביים את חייו?', 'מחזה מצחיק ושנון, המתבונן במבט אירוני על תיאטרון ועל החיים. במרכזו עומדים דניאל וקרין, זוג במשבר נישואין. קרין צעירה מדניאל כמעט בעשרים שנה, ונפער ביניהם פער ערכי עמוק. המציאות הישראלית הכאוטית שוחקת את קרין והיא חולמת לעזוב לברלין. אבל האם דניאל וקרין הם דמויות אמיתיות – או מראות של הקונפליקט הפנימי של אדי, יוצר תיאטרון המנסה לביים את חייו? מחזה חכם, ריאליסטי ומשעשע. מאת ובימוי: דליה שימקו.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (111, 'אקספוז׳ר', 'אקספוז׳ר', 'תמונע', 55, 'הבמאי נדב אמיר, הידוע בהצגות הנשים שלו, עושה הכל כדי לא להיחשף. הוא מלהק שחקנית צעירה למחזה חדש, אך מגלה שהרכבת כבר יצאה לדרך.', 'מה המחיר של לחשוף את הסודות שלך? הבמאי נדב אמיר הידוע בהצגות הנשים שלו, עושה הכל כדי לא להיחשף. יש משהו שהוא חייב לדבר עליו כבר הרבה שנים, אבל מה? הוא מלהק שחקנית צעירה למחזה חדש, מוותר עליה כדי לא להיחשף, אבל מגלה שהרכבת כבר יצאה לדרך, ולא הכל בידיים שלו. מאת ובימוי: אלירן כספי. בהשתתפות: נעם ברמט, אלירן כספי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (112, 'גבירתי הנאווה', 'גבירתי-הנאווה', 'התיאטרון העברי', 150, 'המחזמר הקלאסי האהוב חוזר לבמה בגרסה גדולה, מרגשת, צבעונית ומצחיקה. סיפורם של פרופסור היגינס הנוקשה ומוכרת הפרחים אליזה דוליטל, היוצאים למסע מפתיע של שינוי ואהבה.', 'המחזמר הקלאסי האהוב חוזר לבמה בגרסה גדולה, מרגשת, צבעונית ומצחיקה. סיפורם של פרופסור היגינס הנוקשה ומוכרת הפרחים מהשוק, אליזה דוליטל, היוצאים יחד למסע מפתיע של שינוי ואהבה. עם שירים נצחיים: "הגשם בספרד", "הייתי יכולה לרקוד כל הלילה" ועוד. בכיכובם של נתן דטנר ומיקה צור. בימוי: נתן דטנר. תרגום: דן אלמגור ושרגא פרידמן.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (113, 'בגלל הרוח', 'בגלל-הרוח', 'התיאטרון העברי', 120, 'מחזמר ישראלי חדש ומרגש בכיכובו של שלומי שבת. על חוף תל אביב נולדת אהבה בין עידן, מוזיקאי רומנטי, לבין דפנה, מורה לריקוד. אבל אז מגיע צו 8.', 'מחזמר ישראלי חדש, מרגש ומצחיק, על גבי הלהיטים הגדולים של שלומי שבת ובכיכובו. על חוף תל אביב נולדת אהבה בין עידן, מוזיקאי רומנטי, לבין דפנה, מורה לריקוד שובבה. בדיוק כשהחלום עומד להתגשם — צו 8. עידן יוצא לעזה, מאבד את המפקד שלו, ונשבר. סיפור על אהבה בתקופה של אי ודאות, והדרך חזרה הביתה. מאת ובימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (114, 'עפרה', 'עפרה', 'התיאטרון העברי', 130, 'מחזמר מרגש העוקב אחר חייה ושיריה של עפרה חזה. מילדותה בשכונת התקווה ועד לבמות הגדולות בעולם, עם מגה-להיטים כמו "תפילה", "אם ננעלו", "גלבי" ו"חי".', 'מחזמר מרגש העוקב אחר חייה ושיריה של כוכבת העל הישראלית עפרה חזה. מילדותה בשכונת התקווה ועד לבמות הגדולות בעולם, ממגה-להיטים כמו "תפילה", "אם ננעלו", "גלבי", "חי" ועד לסיפור האישי שלה. "מכתב אהבה לעפרה חזה, דמות שהפכה לסמל, ופסקול של דור שלם." בכיכובם של משה פרץ וליבי פנקר. מאת ובימוי: גדי צדקה ומיכל אמדורסקי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (115, 'התשמע קולי', 'התשמע-קולי', 'התיאטרון העברי', 90, 'סיפור חייה, אהבותיה ושירתה של המשוררת הלאומית רחל. עם שיריה המולחנים: "התשמע קולי", "אורי", "גן נעול", "כינרת" ועוד. מעל 250 הופעות.', 'סיפור חייה, אהבותיה ושירתה של המשוררת הלאומית רחל (רחל בלובשטיין). עם שיריה המולחנים: "התשמע קולי", "אורי", "גן נעול", "שם הרי גולן", "לא שרתי לך ארצי", "רק על עצמי", "כינרת" ועוד. מעל 250 הופעות. בכיכוב יונית טובי. ללא הפסקה. מאת ובימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (116, 'אהבה בהפתעה', 'אהבה-בהפתעה', 'התיאטרון העברי', 90, 'קומדיה משפחתית פרועה על אהבה וזהות. בביקור הפתעה בניו יורק, בן מגלה שמשפחתו השתנתה מן הקצה אל הקצה. סודות, אינטרקום תקוע ואהבה מחדש.', 'קומדיה משפחתית פרועה על אהבה וזהות. בביקור הפתעה בניו יורק, בן מגלה שמשפחתו השתנתה מן הקצה אל הקצה. בנו היחיד נורמן חי חיים שהוא מעולם לא דמיין, עם סודות שמסתתרים עמוק בארון, אינטרקום תקוע, מערכות יחסים מתפוררות ויפהפייה אחת עם תזמון מושלם — הכל מסתחרר לסערה של צחוק ואהבה. מוכיחה שאף פעם לא מאוחר מדי לשחרר שליטה ובעיקר — להתאהב שוב. בימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (117, 'הלב שלי בחר', 'הלב-שלי-בחר', 'התיאטרון העברי', 110, 'מופע מוזיקלי-תיאטרלי חדש בכיכובם של קובי אפללו ומורן אהרוני. מוזיקה, הומור, רגש ושורשים — עם הלהיטים הגדולים: "הלב שלי בחר", "געגועים", "מכתב לאחי" ועוד.', 'מופע מוזיקלי-תיאטרלי חדש בכיכובם של קובי אפללו ומורן אהרוני. מוזיקה, הומור, רגש ושורשים — מופע על אהבה ישנה שלא נשכחת, חתונה אחת שמטריפה את כולם, ומשפחה צבעונית שלא מפסיקה לדבר. עם הלהיטים הגדולים של קובי אפללו: "הלב שלי בחר", "געגועים", "מכתב לאחי" ועוד. מאת ובימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (118, 'אני פה בגלל אשתי', 'אני-פה-בגלל-אשתי', 'התיאטרון העברי', 100, 'מופע הבידור המצליח בכל הזמנים חוזר בגרסה חדשה ומעודכנת! שלושה זוגות ישראליים טיפוסיים מגיעים לקליניקה של ד"ר "נישואים שמחים" — מטפל לא קונבנציונלי.', 'מופע הבידור המצליח בכל הזמנים חוזר בגרסה חדשה ומעודכנת! שלושה זוגות ישראליים טיפוסיים מגיעים לקליניקה של ד"ר "נישואים שמחים" — מומחה לטיפול קבוצתי לא קונבנציונלי. נשואים? יש בעיות? לא יכולים לנשום? רוצים להתגרש? לפני שעושים מהלך לא אחראי — בואו ליהנות מקומדיה מטורפת שמצחיקה עד דמעות. מאת: איזו ליבוביץ. עיבוד: גדי צדקה וארז שלם. בימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (119, 'זוגיות AI', 'זוגיות-AI', 'התיאטרון העברי', 90, 'קומדיה מטורפת בכיכוב יגאל עדיקא. גבר בתהליך פרידה מאשתו מחליט לרכוש אישה מכנית מבוססת AI — אחת שרק תשמח אותו. אבל המציאות מסתבכת.', 'קומדיה מטורפת בכיכוב יגאל עדיקא, שצוחקת על כל מה שהולך לקרות למערכות היחסים שלנו בעידן ה-AI. גבר בתהליך פרידה מאשתו מחליט לרכוש אישה מכנית מבוססת בינה מלאכותית — אחת שרק תשמח אותו, תעשה את כל מה שהוא רוצה, ובעיקר לא תתלונן כל היום. אבל המציאות מסתבכת, והאישה המלאכותית מטריפה את כולם סביבה. מאת: עוזי וייל ורוני סיני. בימוי: אריק אביגדור.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (120, 'הברונית רוטשילד', 'הברונית-רוטשילד', 'התיאטרון העברי', 110, 'מחזה חדש מאת יהונדב צדקה, מלווה בתזמורת חיה על הבמה. "האישה שחצתה גבולות, עולמות ומוסכמות." מה גורם לאישה העשירה ביותר בעולם לנטוש הכל?', 'מחזה חדש מאת יהונדב צדקה, מלווה בתזמורת חיה על הבמה. "האישה שחצתה גבולות, עולמות ומוסכמות." מה גורם לאישה העשירה ביותר בעולם לנטוש הכל? מדוע היא עוזבת את ביתה ומשפחתה בחיפוש אחר פסנתרן אגדי שמעולם לא פגשה? בכיכוב נטע פלוטניק וגיל וינברג. בימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (121, 'מראה מעל הגשר', 'מראה-מעל-הגשר', 'התיאטרון העברי', 120, 'סיפור של בגידה, נקמה וצדק טבעי פרימיטיבי מול מערכות המשפט של החברה המתוקנת. מחזהו הגדול של ארתור מילר בכיכוב נתן דטנר.', 'סיפור של בגידה, נקמה וצדק טבעי פרימיטיבי אל מול מערכות המשפט של החברה המתוקנת. בשכונת מהגרים איטלקיים ליד הנמל בברוקלין, אדי קרבונה (נתן דטנר) ואשתו מגדלים את אחיינית האישה. שני בני דודים שנכנסו לאמריקה בצורה בלתי חוקית מגיעים לבית. סיפורו של "אב" מסור ואוהב שבניסיון נואש לשמור את "בתו" לעצמו, היה מוכן לוותר על משפחתו, כבודו וחייו. נחשב למחזהו הגדול של ארתור מילר. תרגום: דן אלמגור. בימוי: נתן דטנר.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (122, 'צלילי המוסיקה', 'צלילי-המוסיקה', 'התיאטרון העברי', 160, 'לראשונה בישראל — הפקה של המחזמר הקלאסי המצליח בכל הזמנים בגרסתו המלאה, בליווי תזמורת חיה. סיפורה של מריה, הנזירה הצעירה שמשנה את חייה של משפחת פון טראפ.', 'לראשונה בישראל — הפקה של המחזמר הקלאסי המצליח בכל הזמנים בגרסתו המלאה, בליווי תזמורת חיה על הבמה. (אוסטריה, 1938) מריה, נזירה צעירה ושוקקת חיים המתקשה עם כללי המנזר, נשלחת לשמש כאומנת לשבעת ילדיו של הקפטן פון טראפ. היא הופכת את ביתו הקפדני לבית מלא שמחה, צחוק ומוזיקה, כובשת את לבות הילדים ובסופו של דבר גם את לב אביהם. האידיליה מופרת כשהנאצים כובשים את אוסטריה, והמשפחה הצעירה חייבת להתמודד באומץ עם אתגרים וסכנות בדרכם לחיים חדשים. בכיכוב מיקה צור וניר שיבר. בימוי: נתן דטנר.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (123, 'השוטר אזולאי', 'השוטר-אזולאי', 'התיאטרון העברי', 110, 'הפקה בימתית מפוארת ומרגשת של הסרט הישראלי הגדול בכל הזמנים: "השוטר אזולאי" של אפרים קישון. סיפורו של השוטר אברהם אזולאי החולם להתקדם בדרגה.', 'הפקה בימתית מפוארת ומרגשת של הסרט הישראלי הגדול בכל הזמנים: "השוטר אזולאי", סרטו הזוכה של אפרים קישון. סיפורו של השוטר סייר אברהם אזולאי, שאחרי 20 שנות שירות באותה דרגה, חולם להתקדם לדרגת רב"ט ב׳. בכיכוב שלום אסייג. המנהלת המוזיקלית: נורית הירש, חתנית פרס ישראל. מאת ובימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (124, 'כנר על הגג – המחזמר', 'כנר-על-הגג-–-המחזמר', 'התיאטרון העברי', 150, 'המחזמר היהודי הגדול בכל הזמנים, בליווי תזמורת חיה! על פי סיפוריו של שלום עליכם. טוביה החלבן ומשפחתו נאבקים בין מסורת לשינוי.', 'המחזמר היהודי הגדול בכל הזמנים, בליווי תזמורת חיה על הבמה! על פי סיפוריו של שלום עליכם. טוביה החלבן, יהודי עני ואב לחמש בנות, מנסה לשמור על משפחתו לפי מצוות הדת והמסורת בסביבה עוינת ומשתנה. הוא נאבק בבחירות בנותיו הבוגרות בבני זוג, וגזירת גירוש מכריחה את כל יהודי העיירה לעזוב את בתיהם. הפקה מפוארת עם בימוי רגיש ואוהב. בכיכוב נתן דטנר. בימוי: נתן דטנר. גרסה עברית: דן אלמגור.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (125, 'שוקו וניל', 'שוקו-וניל', 'התיאטרון העברי', 90, 'קומדיה ישראלית מרגשת, עוקצנית ומצחיקה עד דמעות. אביבה, ישראלית ממוצא אתיופי, לומדת באוניברסיטת תל אביב ומנסה לשכור דירה ברמת אביב.', 'קומדיה ישראלית מרגשת, עוקצנית ומצחיקה עד דמעות. אביבה, ישראלית ממוצא אתיופי, לומדת באוניברסיטת תל אביב ומנסה לשכור דירה ברמת אביב. האם דיירי השכונה יקבלו את השכנה החדשה? בכיכוב ארז שלם, פנינה ברט, טיטי איינאו ויורם יוספסברג. מאת: גדי צדקה וארז שלם. בימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (126, 'הפרח בגני', 'הפרח-בגני', 'התיאטרון העברי', 130, 'מחזמר חדש וסוחף על חייו של זוהר ארגוב — "המלך" של המוזיקה הישראלית. שירה תימנית, קריירה סוערת, התמכרות וכיסופים עזים לאהבה ולחיים טובים.', 'מחזמר חדש וסוחף על חייו של זוהר ארגוב — "המלך" של המוזיקה הישראלית. סיפורו מקיף שירה תימנית שורשית, ילדות בעוני עם אב אלכוהוליסט ואם אוהבת אך חסרת אונים, קריירה סוערת עם שירים ייחודיים לצד מאבקים חברתיים ואישיים, רצון עז להצליח ולכבוש מקום בלב האומה, לצד התמכרות קשה לסמים ואלימות פורצת לצד כיסופים עזים לאהבה ולחיים טובים. נוגע במיתרים העדינים של החברה הישראלית משנות ה-70 ועד היום. בכיכוב בר צברי. מאת ובימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (127, 'רוחל''ה מתחתנת', 'רוחל׳ה-מתחתנת', 'התיאטרון העברי', 100, 'דרמה קומית מרגשת מאת סביון ליברכט. רוחל''ה, הבת האהובה, סוף סוף מצאה חתן. אביה שלוימה, ניצול שואה, מתנגד בחריפות לחתונה ונחוש לבטל אותה.', 'דרמה קומית מרגשת מאת סביון ליברכט. רוחל''ה, הבת האהובה, סוף סוף מצאה חתן לליבה. מרגע שאביה שלוימה, ניצול שואה אלמן, פוגש את החתן, מתעוררת בו התנגדות עזה והוא נחוש לבטל את חתונת בתו הבכורה. ברקע עולה מערכת היחסים המורכבת בין רוחל''ה לאחותה לאה — גרושה עם ילד — והחברות הנפלאה בין שלוימה לחברו סטאשק שחולקים סוד מימי המלחמה ואהבתם הגדולה לאותה אישה. מחזה מרגש הנוגע בנימי הנפש של החברה הישראלית. בימוי: נתן דטנר.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (128, 'שיעור באהבה', 'שיעור-באהבה', 'התיאטרון העברי', 80, 'קומדיה מצחיקה עד דמעות. סיפורו של פיני, שיפוצניק שלוקח כל עבודה. יום אחד הוא נקלע ל"קליניק און" — קליניקה לשיפור תפקוד מיני — ונדרש למלא מקום מטפל.', 'קומדיה מצחיקה עד דמעות. סיפורו של פיני, שיפוצניק שלוקח כל עבודה כדי להתפרנס. יום אחד הוא נקלע ל"קליניק און" — קליניקה לשיפור תפקוד מיני — לשיפוץ שגרתי. להפתעתו, מבקשים ממנו בדחיפות למלא מקום המטפל הראשי ולתת ייעוץ למטופלים. מאת ובימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (129, 'קברט ז''בוטינסקי', 'קברט-ז׳בוטינסקי', 'התיאטרון העברי', 75, 'זוכה פרס תיאטרונטו 2011. כשסבתא אחת מחליטה לשנות את העולם. לאה ישורון, גננת ותיקנית וחלוצה, יוצאת לשנות את תוכניותיו של ראש הממשלה.', 'זוכה פרס תיאטרונטו 2011. כשסבתא אחת מחליטה לשנות את העולם. לאה ישורון, גננת ותיקנית וחלוצת ארץ ישראל, היא הגננת המיתולוגית של מושבת בנימינה. יום אחד היא שומעת שראש הממשלה — שהיה פעם ילד בגן שלה — עומד להכריז על גיוס כללי של כל החיילים. היא יוצאת לשנות את תוכניותיו. מונודרמה בכיכוב פנינה ברט-צדקה. בימוי: גדי צדקה.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (130, 'אבידן ואלייזה – מופע ספרותי', 'אבידן-ואלייזה-–-מופע-ספרותי', 'תיאטרון הקאמרי', 90, 'במופע ספרותי מרתק, ''אבידן ואלייזה'' חוקר את החזון של דוד אבידן בעידן הבינה המלאכותית, ומעלה שאלות על יצירה, טכנולוגיה ורלוונטיות תרבותית.', 'ההצגה ''אבידן ואלייזה'' מציגה את תובנותיו של דוד אבידן, פסיכיאטור אלקטרוני, ומדגימה את הרלוונטיות של ספרו הנבואי בעידן הבינה המלאכותית, תוך חיבור בין יצירה ספרותית לניסוי אוונגרדי.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (131, 'מחווה לנעמי שמר', 'מחווה-לנעמי-שמר', 'תיאטרון הקאמרי', 90, 'מופע מרגש המוקדש לנעמי שמר, בו נשמעת המוזיקה המוכרת והאהובה שלה, המשלבת בין שירים מקוריים לשירים מתורגמים, ומזמינה את הקהל לחוות את עולמה המוזיקלי.', 'מופע מחווה לכלת פרס ישראל נעמי שמר, שבו יבוצעו שירים שנעמי כתבה והלחינה, שירי משוררים שהיא בחרה להלחין ושירים שהיא תירגמה, כמו ''ירושלים של זהב'' ו''אהבת פועלי הבניין''.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (132, 'רינגו', 'רינגו', 'תיאטרון הקאמרי', 110, 'מחזמר קומי פרוע על אהבה ואינטימיות, שבו איבר מין נעלם ומצית רומן בלתי צפוי, חקירות משטרתיות והשתלבות בצבא.', 'דקות ספורות לאחר שדני דינגוט מציע נישואים למיקה הוא מגלה שאיבר המין שלו נעלם. באותה העת, האיבר שלו – ''רינגו'' - כבר חוגג את עצמאותו ברחבי העיר. מיקה נסחפת לרומן עם רינגו, משטרת ישראל פותחת בחקירה, שלמה ארצי נרתם לעזור, והכל הולך ומסתבך כשרינגו מתגייס לצה"ל. מחזמר קומי פרוע על אהבה ואינטימיות, על המאבק הנצחי בין היגיון לתשוקה ועל התגנבות הפוליטיקה אל תוך התחתונים.') ON CONFLICT (id) DO NOTHING;
INSERT INTO "Show" (id, title, slug, theatre, "durationMinutes", summary, description) VALUES (133, 'AI וחדשנות ספרותית – דוד אבידן ועוד', 'AI-וחדשנות-ספרותית-–-דוד-אבידן-ועוד', 'תיאטרון הקאמרי', 90, 'הצגת דיאלוגים מרתקים בין יצירתיות לטכנולוגיה, המשלבת את דמותו של דוד אבידן בהקשרים של סייבורגים ובינה מלאכותית.', 'ההצגה עוסקת בקשרים בין יצירתיות לטכנולוגיה, תוך חקירת יצירתו של דוד אבידן בהקשרים של אדם-מכונה, סייבורגים ובינה מלאכותית, ומביאה לדיון את השפעתם על התרבות והחינוך.') ON CONFLICT (id) DO NOTHING;
